INSERT INTO `comments` (`id`, `user_id`, `username`, `target_type`, `target_id`, `content`, `reply_to_id`, `reply_to_user_id`, `reply_to_username`, `likes`, `reply_count`, `status`, `created_at`, `updated_at`) VALUES (1,2,'dongyi001','plant',1,'钩藤确实是治疗惊风的良药，我孩子小时候用过，效果很好！',NULL,NULL,NULL,10,2,'approved','2026-03-04 04:47:10','2026-03-12 20:06:01'),(2,3,'herb_fan','plant',2,'透骨草在我们侗寨很常见，老人们常用来治疗跌打损伤。',NULL,NULL,NULL,0,0,'approved','2026-03-04 04:47:10','2026-03-04 04:47:10'),(3,4,'culture_lover','plant',5,'七叶一枝花是珍贵的药材，现在野外越来越少了，需要保护。',NULL,NULL,NULL,0,0,'approved','2026-03-04 04:47:10','2026-03-04 04:47:10'),(4,2,'dongyi001','knowledge',1,'药浴疗法真的很舒服，泡完之后全身轻松，推荐大家试试。',NULL,NULL,NULL,0,0,'approved','2026-03-04 04:47:10','2026-03-04 04:47:10'),(5,3,'herb_fan','knowledge',2,'艾灸疗法对宫寒很有效，我坚持艾灸三个月，身体好多了。',NULL,NULL,NULL,0,0,'approved','2026-03-04 04:47:10','2026-03-04 04:47:10'),(6,5,'test','knowledge',4,'蛇伤急救方很实用，我们山区经常遇到蛇，学习了！',NULL,NULL,NULL,0,0,'approved','2026-03-04 04:47:10','2026-03-04 04:47:10'),(7,2,'dongyi001','inheritor',1,'吴明德老先生是真正的侗医大师，医术精湛，医德高尚。',NULL,NULL,NULL,0,0,'approved','2026-03-04 04:47:10','2026-03-04 04:47:10'),(8,3,'herb_fan','inheritor',2,'杨秀珍奶奶治好了我多年的妇科病，非常感谢！',NULL,NULL,NULL,0,0,'approved','2026-03-04 04:47:10','2026-03-04 04:47:10'),(9,4,'culture_lover','inheritor',3,'石文昌医生的正骨手法很厉害，我父亲的腰伤就是他治好的。',NULL,NULL,NULL,0,0,'approved','2026-03-04 04:47:10','2026-03-04 04:47:10'),(10,5,'test','resource',1,'入门指南写得很详细，对初学者很有帮助。',NULL,NULL,NULL,0,0,'approved','2026-03-04 04:47:10','2026-03-04 04:47:10'),(11,2,'dongyi001','resource',2,'药浴视频教程很实用，跟着学了几次，已经掌握了基本方法。',NULL,NULL,NULL,0,0,'approved','2026-03-04 04:47:10','2026-03-04 04:47:10'),(12,3,'herb_fan','resource',3,'草药图谱很精美，每种药材都有详细说明，值得收藏。',NULL,NULL,NULL,0,0,'approved','2026-03-04 04:47:10','2026-03-04 04:47:10'),(13,1,'admin','quiz',1,'1',NULL,NULL,NULL,0,0,'approved','2026-03-04 07:22:20','2026-03-04 07:22:20'),(14,1,'admin','quiz',1,'2',NULL,NULL,NULL,0,0,'approved','2026-03-05 01:19:15','2026-03-05 01:19:15'),(15,1,'admin','quiz',1,'3',NULL,NULL,NULL,0,0,'rejected','2026-03-05 02:07:25','2026-03-05 02:07:25'),(16,6,'test001','quiz',1,'1111',NULL,NULL,NULL,0,0,'pending','2026-03-06 21:53:20','2026-03-06 21:53:20'),(17,3,'herb_fan','plant',1,'是的，钩藤的效果确实很好，我们家也经常用。',1,2,'dongyi001',0,0,'approved','2026-03-05 10:00:00','2026-03-05 10:00:00'),(18,4,'culture_lover','plant',1,'钩藤在我们侗寨也很常见，是一种很重要的药材。',1,2,'dongyi001',1,1,'approved','2026-03-05 11:00:00','2026-03-12 20:05:58'),(19,2,'dongyi001','plant',1,'谢谢大家的认可，希望更多人了解侗药的价值。',17,3,'herb_fan',0,0,'approved','2026-03-05 12:00:00','2026-03-05 12:00:00');
