  `representative_cases` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '代表案例',
  `honors` varchar(1000) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci DEFAULT NULL COMMENT '荣誉资质',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `view_count` int DEFAULT '0' COMMENT '浏览量',
  `favorite_count` int DEFAULT '0' COMMENT '收藏量',
