INSERT INTO `inheritors` (`id`, `name`, `level`, `bio`, `specialties`, `experience_years`, `videos`, `images`, `documents`, `representative_cases`, `honors`, `created_at`, `view_count`, `favorite_count`, `popularity`, `update_log`) VALUES (1,'谭锦宁','自治区级','谭锦宁，侗族，出生于广西三江侗族自治县。2002年创立谭氏侗族医药传承工作室，2015年被认定为侗族医药代表性传承人，2016年获自治区级非物质文化遗产保护性示范户。长期从事侗族医药临床与传承工作，擅长将传统侗药与现代养生结合。在2020-2022年度广西壮族自治区级非遗代表性传承人评估中获\"优秀\"等次。','侗族医药、骨伤治疗、蛇伤救治、药浴疗法',30,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]','[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor1/800/600\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor1b/800/600\", \"size\": 0, \"type\": \"image\"}]','[{\"path\":\"/documents/pdf/inheritors/f0fd043ec5ff4383a2ad8a462cbc2ff7.pdf\",\"name\":\"广西壮族自治区文化和旅游厅关于公布2020-2022年广西壮族自治区级非遗代表性传承人评估结果名单的通知.pdf\",\"size\":1161779,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/d3dd24cf36c34830b0f0e2eaf3e612ed.pdf\",\"name\":\"2020-2022年广西壮族自治区级非遗代表性传承人评估结果公示.pdf\",\"size\":1581165,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/0dd0e666410b4a94ad4587ce2316095d.pdf\",\"name\":\"柳州市第三批非物质文化遗产项目代表性传承人和第一批非物质文化遗产项目代表性传承团体公示.pdf\",\"size\":1199215,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/228e7dfe73534743960f0303f608e09f.pdf\",\"name\":\"柳州市文化广电和旅游局关于公示2020-2022年自治区级非物质文化遗产项目代表性传承人评估等次的公告.pdf\",\"size\":1332270,\"type\":\"pdf\"}]','[\"成立谭氏侗族医药传承工作室\",\"创办侗药养生体验基地\",\"治疗骨伤蛇伤患者数千例\",\"培养侗医药传承人\"]','[\"广西壮族自治区级非物质文化遗产代表性传承人（2020-2022年评估优秀）\",\"侗族医药保护性示范户\",\"三江侗族自治县非遗传承基地负责人\"]','2026-03-08 01:14:22',32,2,95,'[{\"id\":1773664704366,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682001,\"time\":\"2026-03-08\",\"content\":\"创建传承人：谭锦宁\",\"operator\":\"系统\"}]'),(2,'龙宗花','自治区级','龙宗花，侗族，广西三江侗族自治县人。出身侗医世家，专注于侗族医药特别是妇科及养生疗法的传承，是侗族医药自治区级代表性传承人。长期从事侗族妇科调理与养生保健工作，将传统侗医理论与现代临床实践相结合。在2020-2022年度广西壮族自治区级非遗代表性传承人评估中获\"合格\"等次。','侗族医药、妇科调理、养生保健、药浴',32,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]','[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor2/800/600\", \"size\": 0, \"type\": \"image\"}]','[{\"path\":\"/documents/pdf/inheritors/f0fd043ec5ff4383a2ad8a462cbc2ff7.pdf\",\"name\":\"广西壮族自治区文化和旅游厅关于公布2020-2022年广西壮族自治区级非遗代表性传承人评估结果名单的通知.pdf\",\"size\":1161779,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/d3dd24cf36c34830b0f0e2eaf3e612ed.pdf\",\"name\":\"2020-2022年广西壮族自治区级非遗代表性传承人评估结果公示.pdf\",\"size\":1581165,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/0dd0e666410b4a94ad4587ce2316095d.pdf\",\"name\":\"柳州市第三批非物质文化遗产项目代表性传承人和第一批非物质文化遗产项目代表性传承团体公示.pdf\",\"size\":1199215,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/228e7dfe73534743960f0303f608e09f.pdf\",\"name\":\"柳州市文化广电和旅游局关于公示2020-2022年自治区级非物质文化遗产项目代表性传承人评估等次的公告.pdf\",\"size\":1332270,\"type\":\"pdf\"}]','[\"侗族妇科调理传承\",\"养生保健疗法推广\",\"培养侗医药传承人\"]','[\"广西壮族自治区级非物质文化遗产代表性传承人（2020-2022年评估合格）\",\"侗族医药传承人\",\"三江侗族自治县侗医药传承基地成员\"]','2026-03-08 01:14:22',2,1,88,'[{\"id\": 1773145682002, \"time\": \"2026-03-08\", \"content\": \"创建传承人：龙宗花\", \"operator\": \"系统\"}]'),(3,'吴伟文','自治区级','吴伟文，侗族，广西三江侗族自治县人。侗族医药自治区级代表性传承人，长期从事侗族医药临床与传承工作，擅长侗药配方与药浴疗法。在2020-2022年度广西壮族自治区级非遗代表性传承人评估中获\"合格\"等次。','侗族医药、草药配方、药浴疗法',28,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]','[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor3/800/600\", \"size\": 0, \"type\": \"image\"}]','[{\"path\":\"/documents/pdf/inheritors/f0fd043ec5ff4383a2ad8a462cbc2ff7.pdf\",\"name\":\"广西壮族自治区文化和旅游厅关于公布2020-2022年广西壮族自治区级非遗代表性传承人评估结果名单的通知.pdf\",\"size\":1161779,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/d3dd24cf36c34830b0f0e2eaf3e612ed.pdf\",\"name\":\"2020-2022年广西壮族自治区级非遗代表性传承人评估结果公示.pdf\",\"size\":1581165,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/228e7dfe73534743960f0303f608e09f.pdf\",\"name\":\"柳州市文化广电和旅游局关于公示2020-2022年自治区级非物质文化遗产项目代表性传承人评估等次的公告.pdf\",\"size\":1332270,\"type\":\"pdf\"}]','[\"侗药配方传承\",\"药浴疗法推广\",\"培养侗医药传承人\"]','[\"广西壮族自治区级非物质文化遗产代表性传承人（2020-2022年评估合格）\",\"侗族医药传承人\"]','2026-03-08 01:14:22',23,1,82,'[{\"id\": 1773145682003, \"time\": \"2026-03-08\", \"content\": \"创建传承人：吴伟文\", \"operator\": \"系统\"}]'),(4,'韦丽祥','市级','韦丽祥，侗族，广西三江侗族自治县人。明朝《谭氏医药秘籍》第10代传承人，夜郎侗医药研究传承中心法人代表。柳州市第三批非物质文化遗产项目代表性传承人，擅长侗族医药、骨伤治疗及疑难杂症诊治，精通传统接骨术。','侗族医药、骨伤治疗、疑难杂症、传统接骨',35,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]','[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor4/800/600\", \"size\": 0, \"type\": \"image\"}]','[{\"path\":\"/documents/pdf/inheritors/0dd0e666410b4a94ad4587ce2316095d.pdf\",\"name\":\"柳州市第三批非物质文化遗产项目代表性传承人和第一批非物质文化遗产项目代表性传承团体公示.pdf\",\"size\":1199215,\"type\":\"pdf\"}]','[\"传承明朝《谭氏医药秘籍》\",\"创办夜郎侗医药研究传承中心\",\"传统接骨术治疗骨伤患者\",\"培养侗医药传承人\"]','[\"柳州市第三批非物质文化遗产项目代表性传承人\",\"明朝《谭氏医药秘籍》第10代传承人\",\"夜郎侗医药研究传承中心法人\"]','2026-03-08 01:14:22',2,1,90,'[{\"id\": 1773145682004, \"time\": \"2026-03-08\", \"content\": \"创建传承人：韦丽祥\", \"operator\": \"系统\"}]'),(5,'吴新菊','县级','吴新菊，侗族，广西三江侗族自治县人。侗族鼻炎疗法传承人，三江侗族自治县第七批县级非物质文化遗产项目代表性传承人，柳州市第七批市级非物质文化遗产代表性传承人推荐人选。专注于侗族鼻炎疗法的传承与发展，擅长鼻腔给药、侗药熏蒸等特色疗法。','侗族医药、鼻炎疗法、鼻腔给药、侗药熏蒸',15,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]','[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor5/800/600\", \"size\": 0, \"type\": \"image\"}]','[{\"path\":\"/documents/pdf/inheritors/41efbfddfa3e493195ef3c233ffd63db.pdf\",\"name\":\"三政办发〔2020〕111号+三江侗族自治县人民政府办公室关于公布第五批县级非物质文化遗产项目代表传承人名单的通知.pdf\",\"size\":498424,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/32e975883ca542de8160e43ac0e44423.pdf\",\"name\":\"三江侗族自治县人民政府办公室关于公布 第五批县级非物质文化遗产项目 代表传承人名单的通知.pdf\",\"size\":504340,\"type\":\"pdf\"}]','[\"侗族鼻炎疗法传承\",\"鼻腔给药特色疗法\",\"侗药熏蒸治疗鼻炎\"]','[\"三江侗族自治县第七批县级非物质文化遗产项目代表性传承人\",\"柳州市第七批市级非物质文化遗产代表性传承人推荐人选\",\"侗族鼻炎疗法传承人\"]','2026-03-08 01:14:22',3,0,75,'[{\"id\":1773666853161,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682005,\"time\":\"2026-03-08\",\"content\":\"创建传承人：吴新菊\",\"operator\":\"系统\"}]'),(6,'吴雄娟','县级','吴雄娟，侗族，广西三江侗族自治县人。三江侗族自治县第五批县级非物质文化遗产项目代表性传承人，专注于侗族医药特别是草药配方与妇科调理的传承。','侗族医药、草药配方、妇科调理、药浴疗法',12,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]','[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor6/800/600\", \"size\": 0, \"type\": \"image\"}]','[{\"path\":\"/documents/pdf/inheritors/eb60f9e96baf4475a30e5fea09a00571.pdf\",\"name\":\"关于第七批县级非物质文化遗产项目代表传承人和第二批县级代表性传承团体拟推荐名单的公示.pdf\",\"size\":619932,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/4e8a3c07202045cd822f527fd308203e.pdf\",\"name\":\"柳州市文化广电和旅游局关于公示第七批市级非物质文化遗产项目代表性传承人推荐名单的公告.pdf\",\"size\":1084248,\"type\":\"pdf\"},{\"path\":\"/documents/pdf/inheritors/3898e48bf8de4fb9ac812f881154376d.pdf\",\"name\":\"三江侗族自治县文化体育广电和旅游局关于公布第七批县级非物质文化遗产项目代表传承人和第二批县级代表性传承团体名单的通知.pdf\",\"size\":641964,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/24dd2db8e50b4172ba2a3c1b034174c1.pdf\",\"name\":\"柳州市文化广电和旅游局关于公示第九批市级非物质文化遗产代表性项目名录推荐项目名单的公告.pdf\",\"size\":802515,\"type\":\"pdf\"}]','[\"侗药配方传承\",\"妇科调理疗法\",\"药浴疗法推广\"]','[\"三江侗族自治县第五批县级非物质文化遗产项目代表性传承人\",\"侗族医药传承人\"]','2026-03-08 01:14:22',2,0,68,'[{\"id\":1773667081521,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682006,\"time\":\"2026-03-08\",\"content\":\"创建传承人：吴雄娟\",\"operator\":\"系统\"}]'),(7,'韦海生','县级','韦海生，侗族，广西三江侗族自治县人。侗药浸泡药浴疗法传承人，三江侗族自治县第七批县级非物质文化遗产项目代表性传承人。专注于侗药浸泡药浴疗法的传承与发展，擅长风湿调理、皮肤病治疗等。','侗药浸泡药浴疗法、风湿调理、皮肤病治疗',18,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]','[{\"name\": \"600\", \"path\": \"https://picsum.p