\"size\":1467813,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/0ef686e53e3244c18eeb2de20cceeef1.pdf\",\"name\":\"新晃侗族自治县非物质文化遗产项目第二批代表性传承人推荐名单公示.pdf\",\"size\":1132527,\"type\":\"pdf\"}]','[\"跌打损伤侗医治疗\",\"药浴疗法传承\"]','[\"新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人\",\"2024年度考核合格\",\"新晃侗医药传承人\"]','2026-03-08 01:14:22',1,0,65,'[{\"id\": 1773145682016, \"time\": \"2026-03-08\", \"content\": \"创建传承人：吴谋焕\", \"operator\": \"系统\"}]'),(17,'张祥坤','县级','张祥坤，侗族，1987年出生，湖南省新晃侗族自治县人。新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人（增补），年轻一代侗医药传承人代表。专注于侗族医药特别是草药配方的传承与发展。','侗族医药、草药配方',8,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]','[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor17/800/600\", \"size\": 0, \"type\": \"image\"}]','[{\"path\":\"/documents/pdf/inheritors/cb3a16548aec4476a287075eae7586ce.pdf\",\"name\":\"2024年度新晃县级非遗代表性传承人考核合格人员公示.pdf\",\"size\":1467813,\"type\":\"pdf\"}]','[\"侗药配方学习传承\",\"年轻一代侗医药传承\"]','[\"新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人（增补）\",\"年轻一代侗医药传承人\"]','2026-03-08 01:14:22',0,0,58,'[{\"id\": 1773145682017, \"time\": \"2026-03-08\", \"content\": \"创建传承人：张祥坤\", \"operator\": \"系统\"}]'),(18,'钟泽国','县级','钟泽国，侗族，湖南省新晃侗族自治县人（已故）。新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人，生前专注于侗族医药特别是跌打损伤与药浴疗法的传承工作。','侗族医药、跌打损伤、药浴疗法',35,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]','[{\"name\": \"600\", \"path\": \"https://picsum.photos/seed/inheritor18/800/600\", \"size\": 0, \"type\": \"image\"}]','[{\"path\":\"/documents/pdf/inheritors/0ef686e53e3244c18eeb2de20cceeef1.pdf\",\"name\":\"新晃侗族自治县非物质文化遗产项目第二批代表性传承人推荐名单公示.pdf\",\"size\":1132527,\"type\":\"pdf\"},{\"path\":\"documents/pdf/inheritors/bb05e2d59dc348bda97644cd52560390.pdf\",\"name\":\"新晃侗族自治县非物质文化遗产项目第二批代表性传承人增补人员公示.pdf\",\"size\":823864,\"type\":\"pdf\"}]','[\"跌打损伤侗医治疗\",\"药浴疗法传承\",\"培养侗医药传承人\"]','[\"新晃侗族自治县第二批县级非物质文化遗产项目代表性传承人\",\"侗医药传承人（已故）\"]','2026-03-08 01:14:22',5,2,70,'[{\"id\":1773668017493,\"time\":\"2026-03-16\",\"content\":\"更新传承人信息\",\"operator\":\"管理员\"},{\"id\":1773145682018,\"time\":\"2026-03-08\",\"content\":\"创建传承人：钟泽国\",\"operator\":\"系统\"}]');
