DROP TABLE IF EXISTS `knowledge`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `knowledge` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `title` varchar(200) NOT NULL COMMENT '标题',
  `type` varchar(20) NOT NULL COMMENT '类型: 药方/疗法',
  `therapy_category` varchar(50) DEFAULT NULL COMMENT '疗法分类',
  `disease_category` varchar(50) DEFAULT NULL COMMENT '疾病分类',
  `content` text NOT NULL COMMENT '内容',
  `formula` text COMMENT '配方',
  `usage_method` text COMMENT '用法',
  `steps` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '步骤',
  `images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '相关图片URL列表，JSON数组格式',
  `videos` text COMMENT '视频列表(JSON数组格式)',
  `documents` text COMMENT '相关文档',
  `related_plants` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '关联植物ID  [id1,id2,...]',
  `update_log` text COMMENT '更新日志',
  `popularity` int NOT NULL DEFAULT '0' COMMENT '热度',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `view_count` int DEFAULT '0' COMMENT '浏览量',
  `favorite_count` int DEFAULT '0' COMMENT '收藏量',
  PRIMARY KEY (`id`),
  KEY `idx_type` (`type`),
  KEY `idx_popularity` (`popularity`)
) ENGINE=InnoDB AUTO_INCREMENT=41 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='知识库表';
/*!40101 SET character_set_client = @saved_cs_client */;

