LOCK TABLES `knowledge` WRITE;
/*!40000 ALTER TABLE `knowledge` DISABLE KEYS */;
INSERT INTO `knowledge` (`id`, `title`, `type`, `therapy_category`, `disease_category`, `content`, `formula`, `usage_method`, `steps`, `images`, `videos`, `documents`, `related_plants`, `update_log`, `popularity`, `created_at`, `view_count`, `favorite_count`) VALUES (1,'侗族药浴养生方','药方','药浴疗法','风湿骨痛','侗族药浴是侗族传统疗法的重要组成部分，通过药物煎汤浸泡全身或局部，达到防治疾病的目的。药浴能促进血液循环，祛风除湿，舒筋活络，是侗族人民长期与疾病斗争中积累的宝贵经验。','透骨草30g、艾叶30g、钩藤20g、血藤20g、杜仲15g、金银花15g','将药物加水煎煮30分钟，倒入浴桶中，加水调至适宜温度（40-45℃），浸泡全身20-30分钟，每周2-3次。','[\"准备药材：透骨草、艾叶、钩藤、血藤、杜仲、金银花\",\"加水煎煮30分钟\",\"将药液倒入浴桶\",\"调节水温至40-45℃\",\"全身浸泡20-30分钟\",\"浴后擦干保暖\"]','[]','[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]','[]','[2,13,1,7,8,12]','[{\"id\":1,\"time\":\"2024-03-10\",\"content\":\"创建知识条目\",\"operator\":\"系统\"}]',156,'2026-03-04 04:47:10',9,1),(2,'侗医艾灸疗法','疗法','艾灸疗法','妇科疾病','艾灸疗法是侗族传统外治法之一，以艾叶为主要材料，点燃后熏灼穴位，通过温热刺激达到治病保健的目的。侗族艾灸对妇科疾病、风湿疼痛有显著疗效。','艾叶适量','将艾叶制成艾条或艾柱，点燃后对准穴位熏灼，距离皮肤2-3cm，以患者感觉温热舒适为度，每次15-20分钟。','[\"选取穴位：关元、气海、三阴交等\",\"点燃艾条\",\"对准穴位熏灼\",\"距离皮肤2-3cm\",\"每次15-20分钟\",\"注意防止烫伤\"]',NULL,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[13]','[{\"id\":1,\"time\":\"2024-03-10\",\"content\":\"创建知识条目\",\"operator\":\"系统\"},{\"id\":2,\"time\":\"2024-03-11\",\"content\":\"更新内容描述\",\"operator\":\"管理员\"}]',142,'2026-03-04 04:47:10',44,2),(3,'侗族跌打损伤方','药方','推拿疗法','跌打损伤','侗族民间治疗跌打损伤的经验方，具有活血化瘀、消肿止痛的功效。此方在侗族地区流传已久，对各种跌打损伤有良好疗效。','透骨草30g、八角莲15g、七叶一枝花15g、白及15g、血藤20g','将药物捣烂，加适量白酒调匀，外敷患处，每日换药1-2次。也可煎水内服，每日一剂，分两次服用。','[\"准备药材：透骨草、八角莲、七叶一枝花、白及、血藤\",\"将药物捣烂\",\"加适量白酒调匀\",\"外敷患处\",\"每日换药1-2次\",\"严重者可配合内服\"]',NULL,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[2,4,5,10,7]','[{\"id\": 1773144251003, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族跌打损伤方\", \"operator\": \"系统\"}]',138,'2026-03-04 04:47:10',9,2),(4,'侗医蛇伤急救方','药方','外治疗法','毒蛇咬伤','侗族地区山林茂密，蛇虫众多，侗医积累了丰富的蛇伤治疗经验。八角莲是治疗蛇伤的要药，配合其他药物使用，效果显著。','八角莲30g、七叶一枝花20g、半夏10g、车前草30g','将八角莲、七叶一枝花捣烂外敷伤口周围；同时用车前草、半夏煎水内服，每日一剂。严重者需及时送医。','[\"立即绑扎伤口近心端\",\"清洗伤口\",\"八角莲、七叶一枝花捣烂外敷\",\"车前草、半夏煎水内服\",\"密切观察病情\",\"严重者及时送医\"]',NULL,'[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[4,5,17,18]','[{\"id\": 1773144251004, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医蛇伤急救方\", \"operator\": \"系统\"}]',167,'2026-03-04 04:47:10',3,1),(5,'侗族小儿惊风方','药方','内服疗法','儿科疾病','小儿惊风是侗族地区常见儿科急症，侗医常用钩藤等药物治疗，效果显著。此方在侗族民间流传已久，是侗医儿科的代表性方剂。','钩藤15g、天麻10g、金银花10g、茯苓10g','将药物加水煎煮，取汁分2-3次服用，每日一剂。症状严重者需及时就医。','[\"准备药材：钩藤、天麻、金银花、茯苓\",\"加水煎煮20分钟\",\"取汁分2-3次服用\",\"每日一剂\",\"注意观察患儿情况\",\"严重者及时就医\"]',NULL,NULL,NULL,'[1,11,12,15]','[{\"id\": 1773144251005, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族小儿惊风方\", \"operator\": \"系统\"}]',125,'2026-03-04 04:47:10',7,1),(6,'侗医风湿痹痛方','药方','药浴疗法','风湿骨痛','风湿痹痛是侗族地区常见病，与当地潮湿气候有关。侗医常用祛风除湿的药物治疗，配合药浴效果更佳。','九节茶30g、血藤30g、杜仲20g、钩藤20g、透骨草30g','药物加水煎煮，取汁分两次内服，每日一剂。药渣可加水煎煮后用于药浴。','[\"准备药材：九节茶、血藤、杜仲、钩藤、透骨草\",\"加水煎煮30分钟\",\"取汁分两次内服\",\"药渣加水煎煮\",\"用于药浴\",\"坚持治疗2-4周\"]',NULL,NULL,NULL,'[3,7,8,1,2]','[{\"id\": 1773144251006, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医风湿痹痛方\", \"operator\": \"系统\"}]',148,'2026-03-04 04:47:10',2,0),(7,'侗族产后调理方','药方','内服疗法','妇科疾病','侗族妇女产后常用中药调理身体，促进恢复。此方具有补血活血、温经散寒的功效，是侗族产后调理的经典方。','血藤30g、艾叶20g、杜仲20g、何首乌15g、黄精15g','将药物加水煎煮，取汁分两次服用，每日一剂，连服7-14天。','[\"准备药材：血藤、艾叶、杜仲、何首乌、黄精\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"连服7-14天\",\"注意休息保暖\"]',NULL,NULL,NULL,'[7,13,8,16,9]','[{\"id\": 1773144251007, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族产后调理方\", \"operator\": \"系统\"}]',132,'2026-03-04 04:47:10',1,1),(8,'侗医感冒发热方','药方','内服疗法','感冒发热','侗族民间治疗感冒发热的经验方，具有清热解毒、疏风解表的功效。此方对风热感冒效果尤佳。','金银花30g、鱼腥草20g、车前草20g、艾叶10g','将药物加水煎煮，取汁分2-3次服用，每日一剂。发热严重者可每日两剂。','[\"准备药材：金银花、鱼腥草、车前草、艾叶\",\"加水煎煮20分钟\",\"取汁分2-3次服用\",\"每日一剂\",\"多饮温水\",\"注意休息\"]',NULL,NULL,NULL,'[12,19,18,13]','[{\"id\": 1773144251008, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医感冒发热方\", \"operator\": \"系统\"}]',145,'2026-03-04 04:47:10',1,1),(9,'侗族胃寒呕吐方','药方','内服疗法','消化系统疾病','侗族地区气候潮湿，胃寒呕吐较为常见。侗医常用温中散寒的药物治疗，效果显著。','吴茱萸10g、艾叶15g、茯苓15g、半夏10g','将药物加水煎煮，取汁分两次服用，每日一剂。呕吐严重者可少量多次服用。','[\"准备药材：吴茱萸、艾叶、茯苓、半夏\",\"加水煎煮20分钟\",\"取汁分两次服用\",\"每日一剂\",\"少量多次服用\",\"忌食生冷\"]',NULL,NULL,NULL,'[20,13,15,17]','[{\"id\": 1773144251009, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族胃寒呕吐方\", \"operator\": \"系统\"}]',118,'2026-03-04 04:47:10',1,1),(10,'侗医咳嗽痰多方','药方','内服疗法','呼吸系统疾病','侗族民间治疗咳嗽的经验方，对痰湿咳嗽效果尤佳。此方具有燥湿化痰、止咳平喘的功效。','半夏10g、茯苓15g、鱼腥草20g、金银花15g','将药物加水煎煮，取汁分两次服用，每日一剂。咳嗽严重者可每日两剂。','[\"准备药材：半夏、茯苓、鱼腥草、金银花\",\"加水煎煮20分钟\",\"取汁分两次服用\",\"每日一剂\",\"忌食辛辣油腻\",\"注意保暖\"]',NULL,NULL,NULL,'[17,15,19,12]','[{\"id\": 1773144251010, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医咳嗽痰多方\", \"operator\": \"系统\"}]',126,'2026-03-04 04:47:10',0,0),(11,'侗族糖尿病调理方','药方','内服疗法','糖尿病','侗医称糖尿病为\"消渴症\"，常用滋阴清热、生津止渴的药物治疗。石斛是治疗消渴症的要药。','石斛15g、黄精20g、茯苓15g、何首乌15g','将药物加水煎煮，取汁分两次服用，每日一剂。需长期服用，配合饮食调理。','[\"准备药材：石斛、黄精、茯苓、何首乌\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"需长期服用\",\"配合饮食调理\"]',NULL,NULL,NULL,'[14,9,15,16]','[{\"id\": 1773144251011, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族糖尿病调理方\", \"operator\": \"系统\"}]',108,'2026-03-04 04:47:10',1,0),(12,'侗医失眠多梦方','药方','内服疗法','神经系统疾病','侗族民间治疗失眠的经验方，具有养心安神、滋阴清热的功效。此方对阴虚火旺型失眠效果尤佳。','茯苓20g、何首乌15g、天麻10g、黄精15g','将药物加水煎煮，取汁于睡前服用，每日一剂。','[\"准备药材：茯苓、何首乌、天麻、黄精\",\"加水煎煮30分钟\",\"取汁于睡前服用\",\"每日一剂\",\"保持心情舒畅\",\"睡前避免剧烈活动\"]',NULL,NULL,NULL,'[15,16,11,9]','[{\"id\": 1773144251012, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医失眠多梦方\", \"operator\": \"系统\"}]',112,'2026-03-04 04:47:10',2,0),(13,'侗族腰膝酸软方','药方','内服疗法','骨科疾病','侗族民间治疗腰膝酸软的经验方，具有补肝肾、强筋骨的功效。杜仲是补肾强腰的要药。','杜仲30g、血藤20g、何首乌15g、黄精15g','将药物加水煎煮，取汁分两次服用，每日一剂。也可泡酒服用。','[\"准备药材：杜仲、血藤、何首乌、黄精\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"也可泡酒服用\",\"坚持服用2-4周\"]',NULL,NULL,NULL,'[8,7,16,9]','[{\"id\": 1773144251013, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族腰膝酸软方\", \"operator\": \"系统\"}]',134,'2026-03-04 04:47:10',0,0),(14,'侗医皮肤瘙痒方','药方','外治疗法','皮肤病','侗族民间治疗皮肤瘙痒的经验方，具有祛风止痒、清热解毒的功效。可内服外洗配合使用。','金银花30g、艾叶30g、车前草30g、三颗针20g','将药物加水煎煮，取汁分两次内服；药渣加水煎煮后外洗患处，每日一次。','[\"准备药材：金银花、艾叶、车前草、三颗针\",\"加水煎煮30分钟\",\"取汁分两次内服\",\"药渣加水煎煮\",\"外洗患处\",\"每日一次\"]',NULL,NULL,NULL,'[12,13,18,6]','[{\"id\": 1773144251014, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医皮肤瘙痒方\", \"operator\": \"系统\"}]',98,'2026-03-04 04:47:10',0,0),(15,'侗族拔罐疗法','疗法','拔罐疗法','风湿骨痛','拔罐疗法是侗族传统外治法之一，通过负压吸附皮肤，达到祛风除湿、活血化瘀的目的。侗族拔罐对风湿疼痛、跌打损伤有显著疗效。',NULL,'选用竹罐或玻璃罐，用火燃烧法或抽气法产生负压，吸附于患处或穴位，留罐10-15分钟。','[\"患者取舒适体位\",\"选择拔罐部位\",\"清洁皮肤\",\"用火燃烧法产生负压\",\"吸附于患处\",\"留罐10-15分钟\"]',NULL,NULL,NULL,NULL,'[{\"id\": 1773144251015, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族拔罐疗法\", \"operator\": \"系统\"}]',156,'2026-03-04 04:47:10',0,0),(16,'侗医推拿疗法','疗法','推拿疗法','跌打损伤','推拿疗法是侗族传统外治法之一，通过手法作用于人体体表，达到舒筋活络、行气活血的目的。侗族推拿对跌打损伤、风湿疼痛有显著疗效。',NULL,'根据病情选择推、拿、按、摩、揉、捏等手法，每次治疗20-30分钟，每日或隔日一次。','[\"患者取舒适体位\",\"暴露治疗部位\",\"医者双手涂抹介质\",\"运用推、拿、按、摩等手法\",\"重点治疗患处\",\"每次20-30分钟\"]',NULL,NULL,NULL,NULL,'[{\"id\": 1773144251016, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医推拿疗法\", \"operator\": \"系统\"}]',143,'2026-03-04 04:47:10',0,0),(17,'侗族熏蒸疗法','疗法','熏蒸疗法','风湿骨痛','熏蒸疗法是侗族传统外治法之一，通过药物燃烧或煎煮产生的蒸汽熏蒸患处，达到祛风除湿、活血化瘀的目的。','艾叶50g、透骨草50g、钩藤30g','将药物加水煎煮，用蒸汽熏蒸患处，每次20-30分钟，每日一次。','[\"准备药材：艾叶、透骨草、钩藤\",\"加水煎煮\",\"产生蒸汽\",\"熏蒸患处\",\"每次20-30分钟\",\"注意防止烫伤\"]',NULL,NULL,NULL,'[13,2,1]','[{\"id\": 1773144251017, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族熏蒸疗法\", \"operator\": \"系统\"}]',128,'2026-03-04 04:47:10',0,0),(18,'侗医刮痧疗法','疗法','刮痧疗法','感冒发热','刮痧疗法是侗族传统外治法之一，通过刮拭皮肤达到活血化瘀、祛风解表的目的。侗族刮痧对感冒发热、中暑有显著疗效。','刮痧油适量','用刮痧板蘸取刮痧油，沿经络方向刮拭，以皮肤出现红色瘀点为度。','[\"准备刮痧板和刮痧油\",\"患者取舒适体位\",\"暴露刮痧部位\",\"蘸取刮痧油\",\"沿经络方向刮拭\",\"以皮肤出现瘀点为度\"]',NULL,NULL,NULL,NULL,'[{\"id\": 1773144251018, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医刮痧疗法\", \"operator\": \"系统\"}]',135,'2026-03-04 04:47:10',0,0),(19,'侗族小儿推拿疗法','疗法','推拿疗法','儿科疾病','小儿推拿是侗族儿科常用疗法，通过特定手法作用于小儿特定穴位，达到治病保健的目的。对小儿消化不良、发热、咳嗽等有良好疗效。',NULL,'根据病情选择推、揉、捏、拿等手法，作用于小儿特定穴位，每次15-20分钟。','[\"患儿取舒适体位\",\"医者双手清洁温暖\",\"选择适当手法\",\"作用于特定穴位\",\"力度轻柔\",\"每次15-20分钟\"]',NULL,NULL,NULL,NULL,'[{\"id\": 1773144251019, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族小儿推拿疗法\", \"operator\": \"系统\"}]',118,'2026-03-04 04:47:10',0,0),(20,'侗医火疗疗法','疗法','火疗疗法','风湿骨痛','火疗疗法是侗族传统外治法之一，通过药物燃烧产生的热量作用于患处，达到祛风除湿、温经散寒的目的。','艾叶、透骨草、吴茱萸各适量','将药物研末，用白酒调匀，铺于患处，点燃后快速扑灭，利用余热熏蒸患处。','[\"准备药物：艾叶、透骨草、吴茱萸\",\"研末用白酒调匀\",\"铺于患处\",\"点燃后快速扑灭\",\"利用余热熏蒸\",\"注意防止烫伤\"]',NULL,NULL,NULL,'[13,2,20]','[{\"id\": 1773144251020, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医火疗疗法\", \"operator\": \"系统\"}]',98,'2026-03-04 04:47:10',0,0),(21,'侗族黄疸病方','药方','内服疗法','肝胆疾病','侗医治疗黄疸的经验方，具有清热利湿、利胆退黄的功效。茵陈是治疗黄疸的要药，配伍其他药物效果更佳。','茵陈30g、金钱草30g、虎杖20g、郁金15g','将药物加水煎煮，取汁分两次服用，每日一剂。黄疸严重者可每日两剂。','[\"准备药材：茵陈、金钱草、虎杖、郁金\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"忌食油腻\",\"定期复查肝功能\"]',NULL,NULL,NULL,'[45,46,47,48]','[{\"id\": 1773144251021, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族黄疸病方\", \"operator\": \"系统\"}]',105,'2026-03-04 04:47:10',0,0),(22,'侗医水肿方','药方','内服疗法','水肿','侗族民间治疗水肿的经验方，具有利水渗湿、健脾益气的功效。茯苓、泽泻是利水消肿的要药。','茯苓30g、泽泻20g、猪苓15g、薏苡仁30g','将药物加水煎煮，取汁分两次服用，每日一剂。水肿严重者可每日两剂。','[\"准备药材：茯苓、泽泻、猪苓、薏苡仁\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"限制盐分摄入\",\"定期监测体重\"]',NULL,NULL,NULL,'[15,33,34,32]','[{\"id\": 1773144251022, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医水肿方\", \"operator\": \"系统\"}]',92,'2026-03-04 04:47:10',0,0),(23,'侗族便秘方','药方','内服疗法','消化系统疾病','侗族民间治疗便秘的经验方，具有润肠通便、清热泻下的功效。桃仁、何首乌是润肠通便的要药。','桃仁15g、何首乌20g、火麻仁15g、当归10g','将药物加水煎煮，取汁分两次服用，每日一剂。便秘严重者可每日两剂。','[\"准备药材：桃仁、何首乌、火麻仁、当归\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"多饮水\",\"多食蔬菜水果\"]',NULL,NULL,NULL,'[58,16]','[{\"id\": 1773144251023, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族便秘方\", \"operator\": \"系统\"}]',88,'2026-03-04 04:47:10',0,0),(24,'侗医头痛方','药方','内服疗法','神经系统疾病','侗族民间治疗头痛的经验方，具有平肝息风、通络止痛的功效。天麻、钩藤是治疗头痛的要药。','天麻15g、钩藤20g、川芎10g、白芷10g','将药物加水煎煮，取汁分两次服用，每日一剂。头痛严重者可每日两剂。','[\"准备药材：天麻、钩藤、川芎、白芷\",\"加水煎煮20分钟\",\"取汁分两次服用\",\"每日一剂\",\"保持心情舒畅\",\"避免过度劳累\"]',NULL,NULL,NULL,'[11,1]','[{\"id\": 1773144251024, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医头痛方\", \"operator\": \"系统\"}]',95,'2026-03-04 04:47:10',0,0),(25,'侗族痛经方','药方','内服疗法','妇科疾病','侗族妇女治疗痛经的经验方，具有活血化瘀、温经止痛的功效。益母草、红花是治疗痛经的要药。','益母草30g、红花10g、艾叶15g、当归15g','将药物加水煎煮，取汁分两次服用，每日一剂。于月经前3-5天开始服用。','[\"准备药材：益母草、红花、艾叶、当归\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"月经前3-5天开始服用\",\"注意保暖\"]',NULL,NULL,NULL,'[59,57]','[{\"id\": 1773144251025, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族痛经方\", \"operator\": \"系统\"}]',112,'2026-03-04 04:47:10',0,0),(26,'侗医跌打损伤内服方','药方','内服疗法','跌打损伤','侗族民间治疗跌打损伤的内服方，具有活血化瘀、消肿止痛的功效。乳香、没药是活血止痛的要药。','乳香10g、没药10g、血藤20g、延胡索15g','将药物加水煎煮，取汁分两次服用，每日一剂。也可用白酒浸泡后服用。','[\"准备药材：乳香、没药、血藤、延胡索\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"也可用白酒浸泡服用\",\"忌食辛辣刺激\"]',NULL,NULL,NULL,'[53,54,7,52]','[{\"id\": 1773144251026, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医跌打损伤内服方\", \"operator\": \"系统\"}]',108,'2026-03-04 04:47:10',0,0),(27,'侗族小儿疳积方','药方','内服疗法','儿科疾病','侗族民间治疗小儿疳积的经验方，具有健脾消积、和胃化滞的功效。白术、茯苓是健脾消积的要药。','白术15g、茯苓15g、陈皮10g、山楂15g','将药物加水煎煮，取汁分2-3次服用，每日一剂。也可研末冲服。','[\"准备药材：白术、茯苓、陈皮、山楂\",\"加水煎煮20分钟\",\"取汁分2-3次服用\",\"每日一剂\",\"也可研末冲服\",\"调整饮食结构\"]',NULL,NULL,NULL,'[21,15,23]','[{\"id\": 1773144251027, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族小儿疳积方\", \"operator\": \"系统\"}]',86,'2026-03-04 04:47:10',0,0),(28,'侗医阳痿方','药方','内服疗法','男科疾病','侗族民间治疗阳痿的经验方，具有补肾壮阳、益精填髓的功效。杜仲、肉桂是补肾壮阳的要药。','杜仲30g、肉桂10g、枸杞子20g、淫羊藿15g','将药物加水煎煮，取汁分两次服用，每日一剂。也可用白酒浸泡后服用。','[\"准备药材：杜仲、肉桂、枸杞子、淫羊藿\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"也可用白酒浸泡服用\",\"保持心情舒畅\"]',NULL,NULL,NULL,'[8,42]','[{\"id\": 1773144251028, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医阳痿方\", \"operator\": \"系统\"}]',78,'2026-03-04 04:47:10',0,0),(29,'侗族月经不调方','药方','内服疗法','妇科疾病','侗族妇女治疗月经不调的经验方，具有活血调经、补气养血的功效。益母草、鸡血藤是调经的要药。','益母草30g、鸡血藤30g、当归15g、白芍15g','将药物加水煎煮，取汁分两次服用，每日一剂。于月经干净后开始服用。','[\"准备药材：益母草、鸡血藤、当归、白芍\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"月经干净后开始服用\",\"连服7-14天\"]',NULL,NULL,NULL,'[59,61]','[{\"id\": 1773144251029, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族月经不调方\", \"operator\": \"系统\"}]',98,'2026-03-04 04:47:10',0,0),(30,'侗医胃痛方','药方','内服疗法','消化系统疾病','侗族民间治疗胃痛的经验方，具有温中散寒、理气止痛的功效。吴茱萸、高良姜是温胃止痛的要药。','吴茱萸10g、高良姜15g、陈皮10g、木香10g','将药物加水煎煮，取汁分两次服用，每日一剂。胃痛严重者可每日两剂。','[\"准备药材：吴茱萸、高良姜、陈皮、木香\",\"加水煎煮20分钟\",\"取汁分两次服用\",\"每日一剂\",\"忌食生冷油腻\",\"少食多餐\"]',NULL,NULL,NULL,'[20,44,23,26]','[{\"id\": 1773144251030, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医胃痛方\", \"operator\": \"系统\"}]',92,'2026-03-04 04:47:10',0,0),(31,'侗族关节炎方','药方','药浴疗法','风湿骨痛','侗族民间治疗关节炎的经验方，具有祛风除湿、活血通络的功效。配合药浴使用效果更佳。','透骨草50g、九节茶50g、血藤30g、杜仲30g','将药物加水煎煮30分钟，取汁用于药浴，浸泡患处20-30分钟，每日一次。','[\"准备药材：透骨草、九节茶、血藤、杜仲\",\"加水煎煮30分钟\",\"取汁用于药浴\",\"浸泡患处20-30分钟\",\"每日一次\",\"坚持治疗2-4周\"]',NULL,NULL,NULL,'[2,3,7,8]','[{\"id\": 1773144251031, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族关节炎方\", \"operator\": \"系统\"}]',115,'2026-03-04 04:47:10',0,0),(32,'侗医湿疹方','药方','外治疗法','皮肤病','侗族民间治疗湿疹的经验方，具有清热解毒、祛风止痒的功效。可内服外洗配合使用。','金银花30g、地肤子30g、白鲜皮20g、苦参15g','将药物加水煎煮，取汁分两次内服；药渣加水煎煮后外洗患处，每日一次。','[\"准备药材：金银花、地肤子、白鲜皮、苦参\",\"加水煎煮30分钟\",\"取汁分两次内服\",\"药渣加水煎煮\",\"外洗患处\",\"每日一次\"]',NULL,NULL,NULL,'[12,41]','[{\"id\": 1773144251032, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医湿疹方\", \"operator\": \"系统\"}]',88,'2026-03-04 04:47:10',0,0),(33,'侗族贫血方','药方','内服疗法','血液系统疾病','侗族民间治疗贫血的经验方，具有补气养血、健脾益气的功效。黄精、何首乌是补血的要药。','黄精30g、何首乌20g、当归15g、黄芪20g','将药物加水煎煮，取汁分两次服用，每日一剂。需长期服用。','[\"准备药材：黄精、何首乌、当归、黄芪\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"需长期服用\",\"配合饮食调理\"]',NULL,NULL,NULL,'[9,16]','[{\"id\": 1773144251033, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族贫血方\", \"operator\": \"系统\"}]',82,'2026-03-04 04:47:10',0,0),(34,'侗医高血压方','药方','内服疗法','心血管疾病','侗族民间治疗高血压的经验方，具有平肝潜阳、清热降压的功效。钩藤、天麻是降压的要药。','钩藤30g、天麻15g、菊花15g、夏枯草20g','将药物加水煎煮，取汁分两次服用，每日一剂。需长期服用，定期监测血压。','[\"准备药材：钩藤、天麻、菊花、夏枯草\",\"加水煎煮20分钟\",\"取汁分两次服用\",\"每日一剂\",\"需长期服用\",\"定期监测血压\"]',NULL,NULL,NULL,'[1,11]','[{\"id\": 1773144251034, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医高血压方\", \"operator\": \"系统\"}]',96,'2026-03-04 04:47:10',0,0),(35,'侗族小儿发热方','药方','内服疗法','儿科疾病','侗族民间治疗小儿发热的经验方，具有清热解毒、疏风解表的功效。金银花、鱼腥草是清热解毒的要药。','金银花15g、鱼腥草15g、连翘10g、薄荷5g','将药物加水煎煮，取汁分多次服用，每日一剂。发热严重者可每日两剂。','[\"准备药材：金银花、鱼腥草、连翘、薄荷\",\"加水煎煮15分钟\",\"取汁分多次服用\",\"每日一剂\",\"发热严重者可每日两剂\",\"多饮水\"]',NULL,NULL,NULL,'[12,19]','[{\"id\": 1773144251035, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族小儿发热方\", \"operator\": \"系统\"}]',108,'2026-03-04 04:47:10',0,0),(36,'侗医腰腿痛方','药方','内服疗法','骨科疾病','侗族民间治疗腰腿痛的经验方，具有补肾强腰、活血通络的功效。杜仲、牛膝是强腰健骨的要药。','杜仲30g、牛膝20g、血藤20g、延胡索15g','将药物加水煎煮，取汁分两次服用，每日一剂。也可用白酒浸泡后服用。','[\"准备药材：杜仲、牛膝、血藤、延胡索\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"也可用白酒浸泡服用\",\"避免过度劳累\"]',NULL,NULL,NULL,'[8,60,7,52]','[{\"id\": 1773144251036, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医腰腿痛方\", \"operator\": \"系统\"}]',102,'2026-03-04 04:47:10',0,0),(37,'侗族产后缺乳方','药方','内服疗法','妇科疾病','侗族妇女治疗产后缺乳的经验方，具有通经下乳、补气养血的功效。木通、冬葵子是通乳的要药。','木通10g、冬葵子15g、王不留行15g、黄芪20g','将药物加水煎煮，取汁分两次服用，每日一剂。配合食疗效果更佳。','[\"准备药材：木通、冬葵子、王不留行、黄芪\",\"加水煎煮30分钟\",\"取汁分两次服用\",\"每日一剂\",\"配合食疗效果更佳\",\"保持心情舒畅\"]',NULL,NULL,NULL,'[36,39]','[{\"id\": 1773144251037, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族产后缺乳方\", \"operator\": \"系统\"}]',86,'2026-03-04 04:47:10',1,0),(38,'侗医肩周炎方','药方','药浴疗法','风湿骨痛','侗族民间治疗肩周炎的经验方，具有祛风除湿、活血通络的功效。配合药浴和推拿使用效果更佳。','透骨草50g、艾叶50g、桂枝30g、羌活20g','将药物加水煎煮30分钟，取汁用于药浴，浸泡肩部20-30分钟，每日一次。配合推拿按摩。','[\"准备药材：透骨草、艾叶、桂枝、羌活\",\"加水煎煮30分钟\",\"取汁用于药浴\",\"浸泡肩部20-30分钟\",\"每日一次\",\"配合推拿按摩\"]',NULL,NULL,NULL,'[2,13]','[{\"id\": 1773144251038, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗医肩周炎方\", \"operator\": \"系统\"}]',98,'2026-03-04 04:47:10',1,0),(39,'侗族小儿腹泻方','药方','内服疗法','儿科疾病','侗族民间治疗小儿腹泻的经验方，具有健脾止泻、化湿止泻的功效。白术、茯苓是健脾止泻的要药。','白术10g、茯苓10g、陈皮5g、车前子10g','将药物加水煎煮，取汁分多次服用，每日一剂。腹泻严重者可每日两剂。','[\"准备药材：白术、茯苓、陈皮、车前子\",\"加水煎煮15分钟\",\"取汁分多次服用\",\"每日一剂\",\"腹泻严重者可每日两剂\",\"注意饮食卫生\"]',NULL,NULL,NULL,'[21,15,23]','[{\"id\": 1773144251039, \"time\": \"2026-03-04\", \"content\": \"创建知识条目：侗族小儿腹泻方\", \"operator\": \"系统\"}]',92,'2026-03-04 04:47:10',0,1);
/*!40000 ALTER TABLE `knowledge` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `operation_log`
--

DROP TABLE IF EXISTS `operation_log`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `operation_log` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` int DEFAULT NULL COMMENT '用户ID',
  `username` varchar(50) DEFAULT NULL COMMENT '用户名',
  `module` varchar(50) NOT NULL COMMENT '模块名称',
  `operation` varchar(100) NOT NULL COMMENT '操作描述',
  `type` varchar(20) NOT NULL COMMENT '操作类型: CREATE/UPDATE/DELETE/QUERY',
  `method` varchar(200) DEFAULT NULL COMMENT '请求方法',
  `params` text COMMENT '请求参数',
  `ip` varchar(50) DEFAULT NULL COMMENT 'IP地址',
  `duration` int DEFAULT NULL COMMENT '执行时长(ms)',
  `success` tinyint DEFAULT '1' COMMENT '是否成功: 0失败/1成功',
  `error_msg` text COMMENT '错误信息',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '操作时间',
  PRIMARY KEY (`id`),
  KEY `idx_user_id` (`user_id`),
