--
-- Table structure for table `plants`
--

DROP TABLE IF EXISTS `plants`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `plants` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `name_cn` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '中文名称',
  `name_dong` varchar(100) DEFAULT NULL COMMENT '侗语名称',
  `scientific_name` varchar(200) DEFAULT NULL COMMENT '学名',
  `category` varchar(20) NOT NULL COMMENT '分类: 根茎类/全草类/花叶类/果实类/皮类',
  `usage_way` varchar(20) NOT NULL COMMENT '使用方式: 外用/内服/药浴',
  `habitat` varchar(200) DEFAULT NULL COMMENT '生境',
  `efficacy` varchar(500) DEFAULT NULL COMMENT '功效',
  `story` varchar(2000) DEFAULT NULL COMMENT '药用故事',
  `images` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '图片["url1","url2"]',
  `videos` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '视频',
  `documents` text COMMENT '相关文档',
  `distribution` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci COMMENT '地域分布',
  `difficulty` varchar(20) DEFAULT NULL COMMENT '难度: easy/medium/hard',
  `created_at` datetime DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `view_count` int DEFAULT '0' COMMENT '浏览量',
  `favorite_count` int DEFAULT '0' COMMENT '收藏量',
  `popularity` int DEFAULT '1' COMMENT '热度值',
  `update_log` text,
  PRIMARY KEY (`id`),
  KEY `idx_category` (`category`),
  KEY `idx_usage_way` (`usage_way`),
  KEY `idx_name_cn` (`name_cn`),
  KEY `idx_popularity` (`popularity` DESC)
) ENGINE=InnoDB AUTO_INCREMENT=66 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='植物药材表';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `plants`
--

LOCK TABLES `plants` WRITE;
/*!40000 ALTER TABLE `plants` DISABLE KEYS */;
INSERT INTO `plants` (`id`, `name_cn`, `name_dong`, `scientific_name`, `category`, `usage_way`, `habitat`, `efficacy`, `story`, `images`, `videos`, `documents`, `distribution`, `difficulty`, `created_at`, `view_count`, `favorite_count`, `popularity`, `update_log`) VALUES (1,'钩藤','Meix kgaox','Uncaria rhynchophylla','藤本类','内服','生于山谷、溪边、疏林下，分布于贵州、广西、湖南等地','清热平肝，息风定惊。用于头痛眩晕，感冒夹惊，惊痫抽搐，妊娠子痫。','侗族民间流传，一位老猎人发现山中藤蔓能治小儿惊风。其孙突发高热惊厥，老猎人取此藤煎水服用，孩子很快平静下来。从此侗家人便知道这种带钩的藤能治惊风，代代相传至今。','[{\"name\": \"gouteng1.jpg\", \"path\": \"images/plants/gouteng1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"gouteng2.jpg\", \"path\": \"images/plants/gouteng2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"正德堂本草语-钩藤.mp4\", \"path\": \"videos/plants/正德堂本草语-钩藤.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"广西三江\",\"湖南通道\"]','medium','2026-03-04 04:47:10',14,2,95,'[{\"id\": 1773145682001, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：钩藤\", \"operator\": \"系统\"}]'),(2,'透骨草','Nyenc nyenc','Phryma leptostachya','全草类','外用','生于山坡、林缘、路旁，喜阴湿环境','祛风除湿，舒筋活血，止痛。用于风湿痹痛，筋骨挛缩，寒湿脚气，疮癣肿毒。','传说古时一位侗族药农上山采药，不慎扭伤脚踝，疼痛难忍。他发现路边一种小草，捣烂敷在患处，片刻后疼痛减轻，能继续行走。因能透入筋骨治病，故名透骨草。侗医常用其治疗跌打损伤。','[{\"name\": \"tougucao1.jpg\", \"path\": \"images/plants/tougucao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"tougucao2.jpg\", \"path\": \"images/plants/tougucao2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"贵州深山里的神奇草药透骨香，轻轻一碰香飘满山，看看你认识它吗.mp4\", \"path\": \"videos/plants/贵州深山里的神奇草药透骨香，轻轻一碰香飘满山，看看你认识它吗.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黎平\",\"广西龙胜\",\"湖南新晃\"]','easy','2026-03-04 04:47:10',10,1,85,'[{\"id\": 1773145682002, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：透骨草\", \"operator\": \"系统\"}]'),(3,'九节茶','Jus jeenv','Sarcandra glabra','全草类','内服','生于山坡林下、沟谷阴湿处，海拔400-1500米','清热凉血，活血消斑，祛风通络。用于血热紫斑，紫癜，风湿痹痛，跌打损伤。','侗族地区流传着一个故事：一位侗族老人患风湿多年，行动不便。一天他在山中休息，看到一只受伤的山羊啃食一种植物后伤势好转。老人也尝试服用，风湿果然减轻。因茎有九节，故名九节茶。','[{\"name\": \"jiujiecha1.jpg\", \"path\": \"images/plants/jiujiecha1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"jiujiecha2.jpg\", \"path\": \"images/plants/jiujiecha2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"果实红彤彤的草珊瑚，又名九节茶、九节风，你知道它有什么作用吗 草珊瑚 九节茶 植物科普 一日一植物 药用植物 中草药 药材 草药 采药 草本植物 - 抖音.mp4\", \"path\": \"videos/plants/果实红彤彤的草珊瑚，又名九节茶、九节风，你知道它有什么作用吗 草珊瑚 九节茶 植物科普 一日一植物 药用植物 中草药 药材 草药 采药 草本植物 - 抖音.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州从江\",\"广西融水\",\"湖南靖州\"]','medium','2026-03-04 04:47:10',21,2,88,'[{\"id\": 1773145682003, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：九节茶\", \"operator\": \"系统\"}]'),(4,'八角莲','Begs lianx','Dysosma versipellis','根茎类','外用','生于深山密林下阴湿处，海拔600-2000米','清热解毒，化痰散结，祛瘀消肿。用于痈肿疔疮，瘰疬，咽喉肿痛，跌打损伤，毒蛇咬伤。','八角莲是侗医治疗毒蛇咬伤的要药。传说古时侗寨有人被毒蛇咬伤，生命垂危。一位侗族药师用八角莲捣烂外敷，患者转危为安。从此八角莲成为侗家必备的蛇伤良药，被誉为\"蛇伤圣药\"。','[{\"name\": \"bajiaolian1.jpg\", \"path\": \"images/plants/bajiaolian1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"bajiaolian2.jpg\", \"path\": \"images/plants/bajiaolian2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"中草药——八角莲-科普视频-搜狐视频.mp4\", \"path\": \"videos/plants/中草药——八角莲-科普视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州雷山\",\"广西资源\",\"湖南城步\"]','hard','2026-03-04 04:47:10',5,1,60,'[{\"id\": 1773145682004, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：八角莲\", \"operator\": \"系统\"}]'),(5,'七叶一枝花','Qit yev yix faix','Paris polyphylla','根茎类','内服','生于林下阴湿处，海拔700-2800米','清热解毒，消肿止痛，凉肝定惊。用于疔疮痈肿，咽喉肿痛，蛇虫咬伤，跌扑伤痛，惊风抽搐。','侗族民间称其为\"重楼\"，是治疗疮痈肿毒的特效药。相传古时侗寨流行恶疮，一位侗族药师梦见仙人指点，在深山找到七叶一枝花，治愈了众多患者。从此侗家人将其视为神药。','[{\"name\": \"qiyeyizhihua1.jpg\", \"path\": \"images/plants/qiyeyizhihua1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"qiyeyizhihua2.jpg\", \"path\": \"images/plants/qiyeyizhihua2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"七叶一枝花学名“重楼”，珍贵的蛇药植物，用途与价值了解吗？.mp4\", \"path\": \"videos/plants/七叶一枝花学名“重楼”，珍贵的蛇药植物，用途与价值了解吗？.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州台江\",\"广西兴安\",\"湖南桑植\"]','hard','2026-03-04 04:47:10',59,2,98,'[{\"id\": 1773145682005, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：七叶一枝花\", \"operator\": \"系统\"}]'),(6,'三颗针','Samx kebp zenl','Berberis julianae','根皮类','内服','生于山坡灌丛中，海拔1000-2500米','清热燥湿，泻火解毒。用于湿热泻痢，黄疸，湿疹，咽痛目赤，聤耳流脓，痈肿疮毒。','三颗针因茎上有三叉刺而得名。侗族民间常用其根皮治疗肠胃疾病。传说一位侗族猎人在山中吃了不洁食物，腹痛难忍。他发现三颗针的根皮嚼服后腹痛立止，从此侗家人便用它治疗腹泻痢疾。','[{\"name\": \"sankezhen1.jpg\", \"path\": \"images/plants/sankezhen1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"sankezhen2.jpg\", \"path\": \"images/plants/sankezhen2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"【三颗针】为小檗科植物的根皮或茎皮 每一层叶子底下就长三颗针，这就是小时候上山最头疼的植物。它在你的家乡又叫什么名字呢？今日野寻记带你了解三颗针这味本草.mp4\", \"path\": \"videos/plants/【三颗针】为小檗科植物的根皮或茎皮 每一层叶子底下就长三颗针，这就是小时候上山最头疼的植物。它在你的家乡又叫什么名字呢？今日野寻记带你了解三颗针这味本草.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州剑河\",\"广西三江\",\"湖南芷江\"]','easy','2026-03-04 04:47:10',26,1,90,'[{\"id\": 1773145682006, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：三颗针\", \"operator\": \"系统\"}]'),(7,'血藤','Xeex tongc','Spatholobus suberectus','藤本类','内服','生于山谷林下、灌丛中，攀援于树上','补血，活血，通络。用于月经不调，血虚萎黄，麻木瘫痪，风湿痹痛。','血藤是侗族妇女的常用药。传说古时侗寨一位妇女产后血虚，面色苍白，身体虚弱。侗族药师让她服用血藤煎剂，不久身体恢复健康，面色红润。因能补血活血，侗家人称其为\"血藤\"。','[{\"name\": \"xueteng1.jpg\", \"path\": \"images/plants/xueteng1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"xueteng2.jpg\", \"path\": \"images/plants/xueteng2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"大血藤植物的特征以及用途，我们一起来认识一下它吧.mp4\", \"path\": \"videos/plants/大血藤植物的特征以及用途，我们一起来认识一下它吧.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州榕江\",\"广西融安\",\"湖南会同\"]','medium','2026-03-04 04:47:10',2,1,82,'[{\"id\": 1773145682007, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：血藤\", \"operator\": \"系统\"}]'),(8,'杜仲','Dus zhong','Eucommia ulmoides','皮类','内服','生于山地林中，海拔300-1500米','补肝肾，强筋骨，安胎。用于肾虚腰痛，筋骨无力，妊娠漏血，胎动不安。','杜仲是贵州道地药材，侗族地区广泛分布。侗族民间常用杜仲治疗腰膝酸痛。传说一位侗族老人腰痛多年，服用杜仲后腰痛消失，行走自如。从此杜仲成为侗家强腰健骨的良药。','[{\"name\": \"duzhong1.jpg\", \"path\": \"images/plants/duzhong1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"duzhong2.jpg\", \"path\": \"images/plants/duzhong2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"【百草故事】植物黄金——杜仲.mp4\", \"path\": \"videos/plants/【百草故事】植物黄金——杜仲.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州遵义\",\"贵州黔东南\",\"湖南慈利\"]','easy','2026-03-04 04:47:10',2,0,72,'[{\"id\": 1773145682008, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：杜仲\", \"operator\": \"系统\"}]'),(9,'黄精','Wangc jingl','Polygonatum sibiricum','根茎类','内服','生于林下、灌丛或阴湿山坡，海拔800-2800米','补气养阴，健脾，润肺，益肾。用于脾胃气虚，体倦乏力，胃阴不足，口干食少，肺虚燥咳，精血不足，腰膝酸软。','黄精是侗族常用的滋补药。传说古时侗寨一位老人体弱多病，常年服用黄精后身体强健，活到百岁。侗家人认为黄精能延年益寿，将其视为\"仙草\"，常用于煲汤滋补。','[{\"name\": \"huangjing1.jpg\", \"path\": \"images/plants/huangjing1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"huangjing2.jpg\", \"path\": \"images/plants/huangjing2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"黄精.mp4\", \"path\": \"videos/plants/黄精.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州施秉\",\"广西龙胜\",\"湖南通道\"]','easy','2026-03-04 04:47:10',6,0,70,'[{\"id\": 1773145682009, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：黄精\", \"operator\": \"系统\"}]'),(10,'白及','Begc jil','Bletilla striata','根茎类','内服','生于林下、草丛中，海拔100-3200米','收敛止血，消肿生肌。用于咯血，吐血，外伤出血，疮疡肿毒，皮肤皲裂。','白及是侗医治疗外伤出血的常用药。传说古时侗族猎人在山中受伤，血流不止。他用白及粉末敷在伤口，血立刻止住，伤口很快愈合。从此白及成为侗家必备的外伤止血药。','[{\"name\": \"baiji1.jpg\", \"path\": \"images/plants/baiji1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"baiji2.jpg\", \"path\": \"images/plants/baiji2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"中兽药之白及.mp4\", \"path\": \"videos/plants/中兽药之白及.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州镇远\",\"广西全州\",\"湖南新宁\"]','medium','2026-03-04 04:47:10',2,1,80,'[{\"id\": 1773145682010, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：白及\", \"operator\": \"系统\"}]'),(11,'天麻','Qianc mabl','Gastrodia elata','根茎类','内服','生于林下阴湿处，海拔1200-2000米，多与蜜环菌共生','息风止痉，平抑肝阳，祛风通络。用于肝风内动，惊痫抽搐，眩晕头痛，肢体麻木，手足不遂。','天麻是贵州道地药材，黔东南是天麻的主产区。侗族民间常用天麻治疗头晕头痛。传说一位侗族老人常年头痛，服用天麻后头痛消失。因天麻能治\"诸风\"，侗家人称其为\"定风神草\"。','[{\"name\": \"tianma1.jpg\", \"path\": \"images/plants/tianma1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"tianma2.jpg\", \"path\": \"images/plants/tianma2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"中药材讲解天麻的功效与作用_高清1080P在线观看平台_腾讯视频.mp4\", \"path\": \"videos/plants/中药材讲解天麻的功效与作用_高清1080P在线观看平台_腾讯视频.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州大方\",\"贵州雷山\",\"云南昭通\"]','hard','2026-03-04 04:47:10',2,1,78,'[{\"id\": 1773145682011, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：天麻\", \"operator\": \"系统\"}]'),(12,'金银花','Jinl yinv faix','Lonicera japonica','花类','内服','生于山坡灌丛、疏林中，适应性极强','清热解毒，疏散风热。用于痈肿疔疮，喉痹，丹毒，热毒血痢，风热感冒，温病发热。','金银花是侗族民间常用的清热解毒药。每年春夏之交，侗家人采摘金银花晒干备用。传说古时侗寨流行热病，一位侗族药师用金银花煎水给患者服用，热病很快消退。从此金银花成为侗家清热解毒的首选药。','[{\"name\": \"jinyinhua1.jpg\", \"path\": \"images/plants/jinyinhua1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"jinyinhua2.jpg\", \"path\": \"images/plants/jinyinhua2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"金银花的功效作用全解析-科普视频-搜狐视频.mp4\", \"path\": \"videos/plants/金银花的功效作用全解析-科普视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"广西桂林\",\"湖南怀化\"]','easy','2026-03-04 04:47:10',2,0,75,'[{\"id\": 1773145682012, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：金银花\", \"operator\": \"系统\"}]'),(13,'艾叶','Ngaix yev','Artemisia argyi','叶类','外用','生于路旁、荒地、林缘，分布极广','温经止血，散寒止痛；外用祛湿止痒。用于吐血，衄血，崩漏，月经过多，胎漏下血，少腹冷痛，经寒不调，宫冷不孕。','艾叶是侗族艾灸疗法的主要材料。侗族民间常用艾叶熏蒸治疗风湿。传说古时侗族妇女产后腹痛，用艾叶熏蒸腹部后疼痛消失。从此艾叶成为侗家妇科良药，也是艾灸疗法的必备材料。','[{\"name\": \"aiye1.jpg\", \"path\": \"images/plants/aiye1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"aiye2.jpg\", \"path\": \"images/plants/aiye2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"中草药之艾叶，有关它的一切.mp4\", \"path\": \"videos/plants/中草药之艾叶，有关它的一切.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"广西三江\",\"湖南通道\"]','easy','2026-03-04 04:47:10',3,0,68,'[{\"id\": 1773145682013, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：艾叶\", \"operator\": \"系统\"}]'),(14,'石斛','Xix huf','Dendrobium nobile','全草类','内服','生于树上或岩石上，海拔500-1500米','益胃生津，滋阴清热。用于热病津伤，口干烦渴，胃阴不足，食少干呕，病后虚热不退，阴虚火旺，骨蒸劳热。','石斛是侗族地区的珍稀药材，被称为\"仙草\"。侗族民间常用石斛治疗口干舌燥。传说古时侗寨一位老人常年口渴，服用石斛后症状消失。因石斛生长在悬崖峭壁上，采摘困难，侗家人将其视为珍品。','[{\"name\": \"shihu1.jpg\", \"path\": \"images/plants/shihu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"shihu2.jpg\", \"path\": \"images/plants/shihu2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"石斛的功效与作用有哪些？这些好处你知道吗？正确认识石斛很重要.mp4\", \"path\": \"videos/plants/石斛的功效与作用有哪些？这些好处你知道吗？正确认识石斛很重要.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州赤水\",\"广西靖西\",\"云南文山\"]','hard','2026-03-04 04:47:10',2,0,58,'[{\"id\": 1773145682014, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：石斛\", \"operator\": \"系统\"}]'),(15,'茯苓','Fuf lix','Poria cocos','菌类','内服','生于松树根部，海拔700-1500米','利水渗湿，健脾，宁心。用于水肿尿少，痰饮眩悸，脾虚食少，便溏泄泻，心神不安，惊悸失眠。','茯苓是侗族常用的健脾利湿药。侗族地区松林茂密，盛产茯苓。传说古时侗寨有人患水肿病，服用茯苓后水肿消退。侗家人常用茯苓煲汤，既美味又养生，是侗族食疗的重要材料。','[{\"name\": \"fuling1.jpg\", \"path\": \"images/plants/fuling1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"fuling2.jpg\", \"path\": \"images/plants/fuling2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"茯苓 深度解读 你想知道的关于茯苓一切的东西都在这里能学到.mp4\", \"path\": \"videos/plants/茯苓 深度解读 你想知道的关于茯苓一切的东西都在这里能学到.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州锦屏\",\"安徽岳西\",\"云南普洱\"]','medium','2026-03-04 04:47:10',2,0,65,'[{\"id\": 1773145682015, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：茯苓\", \"operator\": \"系统\"}]'),(16,'何首乌','Hoc soux wux','Polygonum multiflorum','根茎类','内服','生于山坡灌丛、石缝中，海拔200-3000米','解毒，消痈，润肠通便。用于瘰疬疮痈，风疹瘙痒，肠燥便秘；制首乌补肝肾，益精血，乌须发。','何首乌是侗族常用的滋补药。传说古时一位侗族老人头发全白，服用何首乌后头发变黑，身体强健。侗家人认为何首乌能乌发延年，常用其泡酒或煲汤，是侗族养生保健的重要药材。','[{\"name\": \"heshouwu1.jpg\", \"path\": \"images/plants/heshouwu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"heshouwu2.jpg\", \"path\": \"images/plants/heshouwu2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"中药本草何首乌的功效与作用及禁忌_高清1080P在线观看平台_腾讯视频.mp4\", \"path\": \"videos/plants/中药本草何首乌的功效与作用及禁忌_高清1080P在线观看平台_腾讯视频.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"广西河池\",\"湖南湘西\"]','medium','2026-03-04 04:47:10',3,0,62,'[{\"id\": 1773145682016, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：何首乌\", \"operator\": \"系统\"}]'),(17,'半夏','Bany xax','Pinellia ternata','根茎类','内服','生于林下、草丛中，海拔2500米以下','燥湿化痰，降逆止呕，消痞散结。用于湿痰寒痰，咳喘痰多，痰饮眩悸，风痰眩晕，痰厥头痛，呕吐反胃。','半夏是侗医治疗咳嗽的常用药。传说古时侗寨有人患痰咳不止，服用半夏后咳嗽消失。侗族药师常用半夏配伍其他药物治疗各种咳嗽。因半夏有毒，侗医在用药前会进行炮制，确保用药安全。','[{\"name\": \"banxia1.jpg\", \"path\": \"images/plants/banxia1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"banxia2.jpg\", \"path\": \"images/plants/banxia2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"每天学习认识一味中药材——半夏.mp4\", \"path\": \"videos/plants/每天学习认识一味中药材——半夏.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"四川南充\",\"甘肃陇南\"]','hard','2026-03-04 04:47:10',2,0,55,'[{\"id\": 1773145682017, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：半夏\", \"operator\": \"系统\"}]'),(18,'车前草','Cex qianl caox','Plantago asiatica','全草类','内服','生于路旁、田边、荒地，分布极广','清热利尿，祛痰，凉血，解毒。用于水肿尿少，热淋涩痛，暑湿泻痢，痰热咳嗽，吐血衄血，痈肿疮毒。','车前草是侗族民间最常见的草药之一。传说古时一位侗族猎人在山中中暑，口渴难耐。他发现路边有一种草，嚼服后口渴减轻。因常生长在路边车辙中，故名车前草。侗家人常用其清热利尿。','[{\"name\": \"cheqiancao1.jpg\", \"path\": \"images/plants/cheqiancao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"cheqiancao2.jpg\", \"path\": \"images/plants/cheqiancao2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"在马路边发现的本草——车前草.mp4\", \"path\": \"videos/plants/在马路边发现的本草——车前草.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"广西桂林\",\"湖南怀化\"]','easy','2026-03-04 04:47:10',2,0,52,'[{\"id\": 1773145682018, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：车前草\", \"operator\": \"系统\"}]'),(19,'鱼腥草','Yux xingl caox','Houttuynia cordata','全草类','内服','生于沟边、溪边、林下阴湿处','清热解毒，消痈排脓，利尿通淋。用于肺痈吐脓，痰热喘咳，热痢，热淋，痈肿疮毒。','鱼腥草是侗族地区最常见的野菜和药材。侗家人喜欢用鱼腥草凉拌食用，也用它治疗肺热咳嗽。传说古时侗寨有人患肺痈，服用鱼腥草后痊愈。因有特殊腥味，故名鱼腥草，是侗家药食两用的佳品。','[{\"name\": \"yuxingcao1.jpg\", \"path\": \"images/plants/yuxingcao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yuxingcao2.jpg\", \"path\": \"images/plants/yuxingcao2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"鱼腥草的主要成分和用途-科普视频-搜狐视频.mp4\", \"path\": \"videos/plants/鱼腥草的主要成分和用途-科普视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}, {\"name\": \"院子里的中药11--鱼腥草（药食两用，肺痈要药）.mp4\", \"path\": \"videos/plants/院子里的中药11--鱼腥草（药食两用，肺痈要药）.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"四川雅安\",\"云南昭通\"]','easy','2026-03-04 04:47:10',2,0,50,'[{\"id\": 1773145682019, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：鱼腥草\", \"operator\": \"系统\"}]'),(20,'吴茱萸','Wuc zhuw yuv','Evodia rutaecarpa','果实类','内服','生于山坡、路旁、林缘，海拔200-1500米','散寒止痛，降逆止呕，助阳止泻。用于厥阴头痛，寒疝腹痛，寒湿脚气，经行腹痛，脘腹胀痛，呕吐吞酸，五更泄泻。','吴茱萸是侗医治疗胃寒呕吐的常用药。传说古时侗寨有人患胃寒呕吐，服用吴茱萸后症状消失。侗族药师常用吴茱萸配伍其他药物治疗胃寒诸症。吴茱萸也是侗族传统药浴的重要材料。','[{\"name\": \"wuzhuyu1.jpg\", \"path\": \"images/plants/wuzhuyu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"wuzhuyu2.jpg\", \"path\": \"images/plants/wuzhuyu2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"认识中药，制吴茱萸.mp4\", \"path\": \"videos/plants/认识中药，制吴茱萸.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州铜仁\",\"广西百色\",\"湖南湘西\"]','medium','2026-03-04 04:47:10',2,0,48,'[{\"id\": 1773145682020, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：吴茱萸\", \"operator\": \"系统\"}]'),(21,'白术','Begc suc','Atractylodes macrocephala','根茎类','内服','生于山坡林下、灌丛中，海拔800-1800米','健脾益气，燥湿利水，止汗，安胎。用于脾虚食少，腹胀泄泻，痰饮眩悸，水肿，自汗，胎动不安。','白术是侗族常用的健脾药。传说古时侗寨有人脾虚泄泻，久治不愈。一位侗族药师让他服用白术，泄泻很快停止。从此白术成为侗家健脾益气的常用药，也是侗族食疗的重要材料。','[{\"name\": \"baizhu1.jpg\", \"path\": \"images/plants/baizhu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"baizhu2.jpg\", \"path\": \"images/plants/baizhu2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"白术.mp4\", \"path\": \"videos/plants/白术.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"浙江磐安\",\"安徽亳州\"]','medium','2026-03-04 04:47:10',5,0,45,'[{\"id\": 1773145682021, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：白术\", \"operator\": \"系统\"}]'),(22,'苍术','Cangl suc','Atractylodes lancea','根茎类','内服','生于山坡灌丛、草丛中，海拔500-2000米','燥湿健脾，祛风散寒，明目。用于湿阻中焦，脘腹胀满，泄泻，水肿，脚气痿躄，风湿痹痛，风寒感冒，夜盲。','苍术是侗族民间常用的祛湿药。侗族地区气候潮湿，风湿病多发，侗医常用苍术配伍其他药物治疗风湿。传说一位侗族老人患风湿多年，服用苍术后症状明显改善。','[{\"name\": \"cangzhu1.jpg\", \"path\": \"images/plants/cangzhu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"cangzhu2.jpg\", \"path\": \"images/plants/cangzhu2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"每天学习认识一味中药材——苍术.mp4\", \"path\": \"videos/plants/每天学习认识一味中药材——苍术.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"江苏茅山\",\"湖北罗田\"]','medium','2026-03-04 04:47:10',2,0,42,'[{\"id\": 1773145682022, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：苍术\", \"operator\": \"系统\"}]'),(23,'厚朴','Houp pox','Magnolia officinalis','皮类','内服','生于山地林中，海拔300-1500米','燥湿消痰，下气除满。用于湿滞伤中，脘痞吐泻，食积气滞，腹胀便秘，痰饮喘咳。','厚朴是侗医治疗腹胀的常用药。传说古时侗寨有人腹胀如鼓，疼痛难忍。侗族药师用厚朴配伍其他药物，患者服用后腹胀消退。从此厚朴成为侗家消胀除满的要药。','[{\"name\": \"houpo1.jpg\", \"path\": \"images/plants/houpo1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"houpo2.jpg\", \"path\": \"images/plants/houpo2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"厚朴 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/厚朴 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}, {\"name\": \"厚朴，很美的中药名，你知道她来自什么植物吗.mp4\", \"path\": \"videos/plants/厚朴，很美的中药名，你知道她来自什么植物吗.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"四川都江堰\",\"浙江龙泉\"]','hard','2026-03-04 04:47:10',3,0,40,'[{\"id\": 1773145682023, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：厚朴\", \"operator\": \"系统\"}]'),(24,'陈皮','Cencupil','Citrus reticulata','果实类','内服','栽培于丘陵、低山地带，江河湖泊沿岸或平原','理气健脾，燥湿化痰。用于脘腹胀满，食少吐泻，咳嗽痰多。','陈皮是侗族民间常用的理气药。侗家人常在秋冬季节收集橘皮晒干备用。传说古时侗寨有人消化不良，服用陈皮后症状改善。陈皮也是侗族食疗的重要材料，常用于煲汤调味。','[{\"name\": \"chenpi1.jpg\", \"path\": \"images/plants/chenpi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"chenpi2.jpg\", \"path\": \"images/plants/chenpi2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"陈皮的功效与作用：古老的养生宝贝-健康视频-搜狐视频.mp4\", \"path\": \"videos/plants/陈皮的功效与作用：古老的养生宝贝-健康视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"广东新会\",\"贵州黔东南\",\"四川眉山\"]','easy','2026-03-04 04:47:10',2,0,38,'[{\"id\": 1773145682024, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：陈皮\", \"operator\": \"系统\"}]'),(25,'枳壳','Zix qox','Citrus aurantium','果实类','内服','栽培于丘陵、低山地带','理气宽中，行滞消胀。用于胸胁气滞，胀满疼痛，食积不化，痰饮内停，脏器下垂。','枳壳是侗医治疗气滞的常用药。传说古时侗寨有人胸胁胀痛，服用枳壳后症状缓解。侗族药师常用枳壳配伍其他药物治疗各种气滞证。枳壳也是侗族传统药浴的材料之一。','[{\"name\": \"zhiqiao1.jpg\", \"path\": \"images/plants/zhiqiao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"zhiqiao2.jpg\", \"path\": \"images/plants/zhiqiao2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"枳壳.mp4\", \"path\": \"videos/plants/枳壳.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"江西樟树\",\"四川遂宁\"]','easy','2026-03-04 04:47:10',3,0,35,'[{\"id\": 1773145682025, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：枳壳\", \"operator\": \"系统\"}]'),(26,'木香','Mux xangl','Aucklandia lappa','根茎类','内服','生于高山草地、灌丛中，海拔2500-4000米','行气止痛，健脾消食。用于胸胁胀痛，泻痢后重，食积不消，不思饮食。','木香是侗医治疗腹痛的常用药。传说古时侗寨有人腹痛不止，服用木香后疼痛消失。侗族药师常用木香配伍其他药物治疗各种腹痛。木香也是侗族传统配方的重要组成部分。','[{\"name\": \"muxiang1.jpg\", \"path\": \"images/plants/muxiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"muxiang2.jpg\", \"path\": \"images/plants/muxiang2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"木香 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/木香 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"云南丽江\",\"贵州黔东南\",\"四川阿坝\"]','hard','2026-03-04 04:47:10',2,0,32,'[{\"id\": 1773145682026, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：木香\", \"operator\": \"系统\"}]'),(27,'砂仁','Sax renl','Amomum villosum','果实类','内服','生于山谷林下阴湿处，海拔100-800米','化湿开胃，温脾止泻，理气安胎。用于湿浊中阻，脘痞不饥，脾胃虚寒，呕吐泄泻，妊娠恶阻，胎动不安。','砂仁是侗族常用的化湿药。传说古时侗寨有人脾胃虚寒，食欲不振。侗族药师让他服用砂仁，食欲很快恢复。砂仁也是侗族孕妇常用的安胎药，被视为侗家妇科良药。','[{\"name\": \"sharen1.jpg\", \"path\": \"images/plants/sharen1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"sharen2.jpg\", \"path\": \"images/plants/sharen2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"砂仁 深度解读  教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/砂仁 深度解读  教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"广东阳春\",\"云南西双版纳\",\"贵州黔东南\"]','medium','2026-03-04 04:47:10',3,0,30,'[{\"id\": 1773145682027, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：砂仁\", \"operator\": \"系统\"}]'),(28,'薏苡仁','Yiv yix renl','Coix lacryma-jobi','种子类','内服','栽培于屋旁、河边、溪涧或阴湿山谷中','利水渗湿，健脾止泻，除痹，排脓，解毒散结。用于水肿，脚气，小便不利，脾虚泄泻，湿痹拘挛，肺痈，肠痈，赘疣，癌肿。','薏苡仁是侗族民间常用的利湿药，也是常见的杂粮。侗家人常用薏苡仁煲粥食用，既美味又养生。传说古时侗寨有人患水肿病，服用薏苡仁后水肿消退。薏苡仁是侗族药食两用的代表。','[{\"name\": \"yiyiren1.jpg\", \"path\": \"images/plants/yiyiren1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yiyiren2.jpg\", \"path\": \"images/plants/yiyiren2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"药食同源的薏苡仁｜长在叶片里的小籽.mp4\", \"path\": \"videos/plants/药食同源的薏苡仁｜长在叶片里的小籽.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"福建浦城\",\"辽宁辽阳\"]','easy','2026-03-04 04:47:10',2,0,28,'[{\"id\": 1773145682028, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：薏苡仁\", \"operator\": \"系统\"}]'),(29,'泽泻','Zec xeeb','Alisma orientale','根茎类','内服','生于沼泽边缘、水塘、水沟等浅水处','利水渗湿，泄热，化浊降脂。用于小便不利，水肿胀满，泄泻尿少，痰饮眩晕，热淋涩痛，高脂血症。','泽泻是侗医治疗水肿的常用药。传说古时侗寨有人患水肿病，小便不利。侗族药师让他服用泽泻，水肿很快消退。泽泻也是侗族利水渗湿的重要药材。','[{\"name\": \"zexie1.jpg\", \"path\": \"images/plants/zexie1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"zexie2.jpg\", \"path\": \"images/plants/zexie2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"泽泻 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/泽泻 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"福建建瓯\",\"贵州黔东南\",\"四川彭山\"]','medium','2026-03-04 04:47:10',2,0,25,'[{\"id\": 1773145682029, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：泽泻\", \"operator\": \"系统\"}]'),(30,'猪苓','Jux lix','Polyporus umbellatus','菌类','内服','生于林中树根旁地上或腐木桩旁，海拔800-2000米','利水渗湿。用于小便不利，水肿胀满，脚气，泄泻，淋浊，带下。','猪苓是侗族常用的利水药。侗族地区山林茂密，盛产猪苓。传说古时侗寨有人小便不利，服用猪苓后症状改善。猪苓常与茯苓配伍使用，是侗医利水渗湿的经典组合。','[{\"name\": \"zhuling1.jpg\", \"path\": \"images/plants/zhuling1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"zhuling2.jpg\", \"path\": \"images/plants/zhuling2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"猪苓 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/猪苓 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"陕西留坝\",\"贵州黔东南\",\"云南丽江\"]','medium','2026-03-04 04:47:10',2,0,22,'[{\"id\": 1773145682030, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：猪苓\", \"operator\": \"系统\"}]'),(31,'滑石','Huax six','Talcum','矿物类','外用','产于变质岩地区，由富含镁的岩石经热液蚀变而成','利尿通淋，清热解暑；外用祛湿敛疮。用于热淋，石淋，尿热涩痛，暑湿烦渴，湿热水泻；外治湿疹，湿疮，痱子。','滑石是侗医治疗热淋的常用药。侗族民间常用滑石配伍其他药物治疗泌尿系统疾病。滑石也是侗族夏季常用的清热解暑药，常用于治疗痱子。','[{\"name\": \"huashi1.jpg\", \"path\": \"images/plants/huashi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"huashi2.jpg\", \"path\": \"images/plants/huashi2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"滑石 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/滑石 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"山东平度\",\"广西桂林\",\"辽宁海城\"]','easy','2026-03-04 04:47:10',2,0,20,'[{\"id\": 1773145682031, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：滑石\", \"operator\": \"系统\"}]'),(32,'木通','Mux tongl','Akebia quinata','藤本类','内服','生于山坡、山沟、疏林、灌丛中，海拔250-2000米','利尿通淋，清心除烦，通经下乳。用于淋证，水肿，心烦尿赤，口舌生疮，经闭乳少，湿热痹痛。','木通是侗医治疗淋证的常用药。传说古时侗寨有人小便涩痛，服用木通后症状缓解。侗族药师常用木通配伍其他药物治疗泌尿系统疾病。木通也是侗族通经下乳的重要药材。','[{\"name\": \"mutong1.jpg\", \"path\": \"images/plants/mutong1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"mutong2.jpg\", \"path\": \"images/plants/mutong2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"木通 深度解读 教你一些你能用到知识.mp4\", \"path\": \"videos/plants/木通 深度解读 教你一些你能用到知识.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"江苏南京\",\"浙江杭州\"]','medium','2026-03-04 04:47:10',2,0,18,'[{\"id\": 1773145682032, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：木通\", \"operator\": \"系统\"}]'),(33,'瞿麦','Qux maix','Dianthus superbus','全草类','内服','生于山坡、草地、路旁或林下，海拔500-2500米','利尿通淋，破血通经。用于热淋，血淋，石淋，小便不通，淋沥涩痛，经闭瘀阻。','瞿麦是侗族民间治疗淋证的常用药。传说古时侗寨有人患石淋，小便疼痛难忍。侗族药师让他服用瞿麦，症状逐渐改善。瞿麦也是侗族通经活血的重要药材。','[{\"name\": \"qumai1.jpg\", \"path\": \"images/plants/qumai1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"qumai2.jpg\", \"path\": \"images/plants/qumai2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"869017da2b1e466ba51ddc393acf5c7d.mp4\", \"path\": \"videos/plants/869017da2b1e466ba51ddc393acf5c7d.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"河北安国\",\"安徽亳州\"]','easy','2026-03-04 04:47:10',9,0,15,'[{\"id\": 1773145682033, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：瞿麦\", \"operator\": \"系统\"}]'),(34,'萹蓄','Bianx xux','Polygonum aviculare','全草类','内服','生于路旁、田边、荒地、水边湿地，分布极广','利尿通淋，杀虫，止痒。用于热淋，小便短赤，淋沥涩痛，皮肤湿疹，阴痒带下。','萹蓄是侗族民间最常见的草药之一。传说古时侗寨有人小便涩痛，服用萹蓄后症状缓解。萹蓄也是侗族治疗皮肤湿疹的常用药，外用内服均可。','[{\"name\": \"bianxu1.jpg\", \"path\": \"images/plants/bianxu1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"bianxu2.jpg\", \"path\": \"images/plants/bianxu2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"296 萹蓄——萹蓄——又名扁竹、粉节草、道生草、蚂蚁草.mp4\", \"path\": \"videos/plants/296 萹蓄——萹蓄——又名扁竹、粉节草、道生草、蚂蚁草.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"河南禹州\",\"山东平邑\"]','easy','2026-03-04 04:47:10',3,0,12,'[{\"id\": 1773145682034, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：萹蓄\", \"operator\": \"系统\"}]'),(35,'海金沙','Haix jinl sax','Lygodium japonicum','孢子类','内服','生于山坡林下、灌丛中、溪边阴湿处，海拔100-1500米','清利湿热，通淋止痛。用于热淋，砂淋，石淋，血淋，膏淋，尿道涩痛。','海金沙是侗医治疗石淋的特效药。传说古时侗寨有人患肾结石，疼痛难忍。侗族药师让他服用海金沙，结石逐渐排出。海金沙是侗族治疗泌尿系统结石的重要药材。','[{\"name\": \"haijinsha1.jpg\", \"path\": \"images/plants/haijinsha1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"haijinsha2.jpg\", \"path\": \"images/plants/haijinsha2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"中草药——海金沙的作用和故事.mp4\", \"path\": \"videos/plants/中草药——海金沙的作用和故事.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"广东广宁\",\"浙江金华\"]','medium','2026-03-04 04:47:10',2,0,10,'[{\"id\": 1773145682035, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：海金沙\", \"operator\": \"系统\"}]'),(36,'石韦','Xix weix','Pyrrosia lingua','全草类','内服','生于林下岩石上或树干上，海拔100-1800米','利尿通淋，清肺止咳，凉血止血。用于热淋，血淋，石淋，小便不通，淋沥涩痛，肺热喘咳，吐血，衄血，尿血，崩漏。','石韦是侗族民间治疗淋证的常用药。传说古时侗寨有人小便涩痛带血，服用石韦后症状缓解。石韦也是侗族治疗肺热咳嗽的重要药材，具有清肺止咳的功效。','[{\"name\": \"shiwei1.jpg\", \"path\": \"images/plants/shiwei1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"shiwei2.jpg\", \"path\": \"images/plants/shiwei2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"石韦.mp4\", \"path\": \"videos/plants/石韦.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"四川峨眉山\",\"浙江天台\"]','medium','2026-03-04 04:47:10',4,0,8,'[{\"id\": 1773145682036, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：石韦\", \"operator\": \"系统\"}]'),(37,'冬葵子','Dongl kuix zix','Abutilon theophrasti','种子类','内服','生于路旁、荒地、田野间，分布极广','清热利尿，消肿。用于尿闭，水肿，口渴，尿少涩痛，乳汁不通。','冬葵子是侗族民间常用的利尿药。传说古时侗寨有人小便不利，服用冬葵子后症状改善。冬葵子也是侗族通乳的重要药材，常用于产后乳汁不通。','[{\"name\": \"dongkuizi1.jpg\", \"path\": \"images/plants/dongkuizi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"dongkuizi2.jpg\", \"path\": \"images/plants/dongkuizi2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"冬葵子.mp4\", \"path\": \"videos/plants/冬葵子.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"河南南阳\",\"山东济南\"]','easy','2026-03-04 04:47:10',5,0,5,'[{\"id\": 1773145682037, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：冬葵子\", \"operator\": \"系统\"}]'),(38,'灯心草','Denl xinl caox','Juncus effusus','全草类','内服','生于水旁、田边、潮湿处，分布极广','清心火，利小便。用于心烦失眠，尿少涩痛，口舌生疮。','灯心草是侗族民间常用的清心药。传说古时侗寨有人心烦失眠，口舌生疮。侗族药师让他服用灯心草，症状很快缓解。灯心草也是侗族治疗小儿夜啼的常用药。','[{\"name\": \"dengxincao1.jpg\", \"path\": \"images/plants/dengxincao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"dengxincao2.jpg\", \"path\": \"images/plants/dengxincao2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"灯心草植物的特征以及用途，我们一起来认识一下它吧.mp4\", \"path\": \"videos/plants/灯心草植物的特征以及用途，我们一起来认识一下它吧.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"江苏苏州\",\"浙江杭州\"]','easy','2026-03-04 04:47:10',2,0,3,'[{\"id\": 1773145682038, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：灯心草\", \"operator\": \"系统\"}]'),(39,'地肤子','Dix fux zix','Kochia scoparia','果实类','内服','生于村边、屋旁、路旁、荒地，分布极广','清热利湿，祛风止痒。用于小便涩痛，阴痒带下，风疹，湿疹，皮肤瘙痒。','地肤子是侗族民间治疗皮肤瘙痒的常用药。传说古时侗寨有人患湿疹，瘙痒难忍。侗族药师让他服用地肤子，症状很快缓解。地肤子也是侗族治疗妇科疾病的常用药。','[{\"name\": \"difuzi1.jpg\", \"path\": \"images/plants/difuzi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"difuzi2.jpg\", \"path\": \"images/plants/difuzi2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"倪海厦《神农本草经》第075味药：地肤子.mp4\", \"path\": \"videos/plants/倪海厦《神农本草经》第075味药：地肤子.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"河北安国\",\"山东平邑\"]','easy','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682039, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：地肤子\", \"operator\": \"系统\"}]'),(40,'茵陈','Yinv cenc','Artemisia capillaris','全草类','内服','生于山坡、路旁、河岸、沙地，分布极广','清利湿热，利胆退黄。用于黄疸尿少，湿温暑湿，湿疮瘙痒。','茵陈是侗医治疗黄疸的特效药。传说古时侗寨有人患黄疸病，皮肤发黄。侗族药师让他服用茵陈，黄疸很快消退。茵陈是侗族治疗肝胆疾病的重要药材。','[{\"name\": \"yinchen1.jpg\", \"path\": \"images/plants/yinchen1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yinchen2.jpg\", \"path\": \"images/plants/yinchen2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"遇见菊科植物“茵陈”，有着草中之“人参”，能当野菜或制茶.mp4\", \"path\": \"videos/plants/遇见菊科植物“茵陈”，有着草中之“人参”，能当野菜或制茶.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"陕西蒲城\",\"江西樟树\"]','easy','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682040, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：茵陈\", \"operator\": \"系统\"}]'),(41,'金钱草','Jinl qianc caox','Lysimachia christinae','全草类','内服','生于沟边、路旁阴湿处，海拔100-2000米','利湿退黄，利尿通淋，解毒消肿。用于黄疸尿赤，热淋，石淋，小便涩痛，痈肿疔疮，毒蛇咬伤。','金钱草是侗医治疗胆结石的特效药。传说古时侗寨有人患胆结石，疼痛难忍。侗族药师让他服用金钱草，结石逐渐排出。金钱草也是侗族治疗黄疸的重要药材。','[{\"name\": \"jinqiancao1.jpg\", \"path\": \"images/plants/jinqiancao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"jinqiancao2.jpg\", \"path\": \"images/plants/jinqiancao2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"金钱草的功效与作用.mp4\", \"path\": \"videos/plants/金钱草的功效与作用.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"四川乐山\",\"贵州黔东南\",\"浙江杭州\"]','easy','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682041, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：金钱草\", \"operator\": \"系统\"}]'),(42,'虎杖','Hux zhangx','Polygonum cuspidatum','根茎类','内服','生于山谷、溪边、路旁，海拔100-2000米','利湿退黄，清热解毒，散瘀止痛，止咳化痰。用于湿热黄疸，淋浊，带下，风湿痹痛，痈肿疮毒，水火烫伤，经闭，癥瘕，跌打损伤，肺热咳嗽。','虎杖是侗族民间常用的清热解毒药。传说古时侗寨有人患黄疸，服用虎杖后症状改善。虎杖也是侗族治疗跌打损伤的重要药材，具有散瘀止痛的功效。','[{\"name\": \"huzhang1.jpg\", \"path\": \"images/plants/huzhang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"huzhang2.jpg\", \"path\": \"images/plants/huzhang2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"虎杖的功效与作用和用量你知道多少.mp4\", \"path\": \"videos/plants/虎杖的功效与作用和用量你知道多少.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"江苏南京\",\"浙江杭州\"]','medium','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682042, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：虎杖\", \"operator\": \"系统\"}]'),(43,'垂盆草','Cuix penc caox','Sedum sarmentosum','全草类','内服','生于山坡岩石上、沟边、路旁湿润处，海拔1600米以下','利湿退黄，清热解毒。用于湿热黄疸，小便不利，痈肿疮疡。','垂盆草是侗医治疗黄疸的常用药。传说古时侗寨有人患黄疸病，服用垂盆草后黄疸消退。垂盆草也是侗族治疗痈肿疮疡的重要药材，外用内服均可。','[{\"name\": \"chuipencao1.jpg\", \"path\": \"images/plants/chuipencao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"chuipencao2.jpg\", \"path\": \"images/plants/chuipencao2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"央视4台（中华医药)里介绍的“仙”草，原来长这样！学名垂盆草.mp4\", \"path\": \"videos/plants/央视4台（中华医药)里介绍的“仙”草，原来长这样！学名垂盆草.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"江苏南京\",\"浙江杭州\"]','easy','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682043, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：垂盆草\", \"operator\": \"系统\"}]'),(44,'附子','Fux zix','Aconitum carmichaeli','根茎类','内服','生于山地草坡、灌丛中，海拔1000-2500米','回阳救逆，补火助阳，散寒止痛。用于亡阳虚脱，肢冷脉微，心阳不足，胸痹心痛，虚寒吐泻，脘腹冷痛，肾阳虚衰，阳痿宫冷，阴寒水肿，阳虚外感，寒湿痹痛。','附子是侗医治疗亡阳虚脱的急救药。传说古时侗寨有人虚脱昏迷，侗族药师用附子煎水灌服，患者转危为安。因附子有毒，侗医在用药前会严格炮制，确保用药安全。','[{\"name\": \"fuzi1.jpg\", \"path\": \"images/plants/fuzi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"fuzi2.jpg\", \"path\": \"images/plants/fuzi2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"【百草故事】“回阳救逆”第一品——附子.mp4\", \"path\": \"videos/plants/【百草故事】“回阳救逆”第一品——附子.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"四川江油\",\"贵州黔东南\",\"云南丽江\"]','hard','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682044, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：附子\", \"operator\": \"系统\"}]'),(45,'干姜','Ganl jiangl','Zingiber officinale','根茎类','内服','栽培于温暖湿润的环境','温中散寒，回阳通脉，温肺化饮。用于脘腹冷痛，呕吐泄泻，肢冷脉微，寒饮喘咳。','干姜是侗族民间常用的温中药。侗家人常在冬季用干姜煲汤驱寒。传说古时侗寨有人脘腹冷痛，服用干姜后症状缓解。干姜也是侗族治疗寒饮喘咳的重要药材。','[{\"name\": \"ganjiang1.jpg\", \"path\": \"images/plants/ganjiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"ganjiang2.jpg\", \"path\": \"images/plants/ganjiang2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"认识国药之干姜.mp4\", \"path\": \"videos/plants/认识国药之干姜.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"四川犍为\",\"云南罗平\"]','easy','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682045, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：干姜\", \"operator\": \"系统\"}]'),(46,'肉桂','Rouc guix','Cinnamomum cassia','皮类','内服','生于常绿阔叶林中，但多为栽培','补火助阳，引火归元，散寒止痛，温通经脉。用于阳痿宫冷，腰膝冷痛，肾虚作喘，眩晕目赤，心腹冷痛，虚寒吐泻，寒疝腹痛，痛经经闭。','肉桂是侗医治疗肾阳虚的常用药。传说古时侗寨有人腰膝冷痛，服用肉桂后症状改善。肉桂也是侗族食疗的重要调料，常用于煲汤调味，既美味又养生。','[{\"name\": \"rougui1.jpg\", \"path\": \"images/plants/rougui1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"rougui2.jpg\", \"path\": \"images/plants/rougui2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"每天学习认识一味中药材——肉桂.mp4\", \"path\": \"videos/plants/每天学习认识一味中药材——肉桂.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"广西防城\",\"广东高要\",\"贵州黔东南\"]','medium','2026-03-04 04:47:10',3,0,1,'[{\"id\": 1773145682046, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：肉桂\", \"operator\": \"系统\"}]'),(48,'小茴香','Xiaox huix xangl','Foeniculum vulgare','果实类','内服','栽培于园圃、田边，适应性极强','散寒止痛，理气和胃。用于寒疝腹痛，睾丸偏坠，痛经，少腹冷痛，脘腹胀痛，食少吐泻。','小茴香是侗族民间常用的温里药。侗家人常用小茴香作为调料，也用它治疗寒疝腹痛。传说古时侗寨有人患寒疝，服用小茴香后症状缓解。小茴香也是侗族治疗胃寒的常用药。','[{\"name\": \"xiaohuixiang1.jpg\", \"path\": \"images/plants/xiaohuixiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"xiaohuixiang2.jpg\", \"path\": \"images/plants/xiaohuixiang2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"神奇中草药：小茴香的功效和作用-健康视频-搜狐视频.mp4\", \"path\": \"videos/plants/神奇中草药：小茴香的功效和作用-健康视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"山西太谷\",\"贵州黔东南\",\"甘肃民勤\"]','easy','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682048, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：小茴香\", \"operator\": \"系统\"}]'),(49,'丁香','Dingl xangl','Syzygium aromaticum','花蕾类','内服','原产马来群岛及印度尼西亚，现我国广东、海南有栽培','温中降逆，补肾助阳。用于脾胃虚寒，呃逆呕吐，食少吐泻，心腹冷痛，肾虚阳痿。','丁香是侗医治疗呃逆的特效药。传说古时侗寨有人呃逆不止，服用丁香后呃逆停止。丁香也是侗族食疗的重要调料，常用于炖肉调味，既美味又温中。','[{\"name\": \"dingxiang1.jpg\", \"path\": \"images/plants/dingxiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"dingxiang2.jpg\", \"path\": \"images/plants/dingxiang2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"认识中草药——丁香-科普视频-搜狐视频.mp4\", \"path\": \"videos/plants/认识中草药——丁香-科普视频-搜狐视频.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"广东广州\",\"海南万宁\",\"广西南宁\"]','medium','2026-03-04 04:47:10',7,0,1,'[{\"id\": 1773145682049, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：丁香\", \"operator\": \"系统\"}]'),(50,'高良姜','Gaol liangc jiangl','Alpinia officinarum','根茎类','内服','生于山坡、疏林下，海拔100-800米','温胃止呕，散寒止痛。用于脘腹冷痛，胃寒呕吐，嗳气吞酸。','高良姜是侗族民间常用的温胃药。传说古时侗寨有人胃寒呕吐，服用高良姜后症状缓解。高良姜也是侗族治疗脘腹冷痛的重要药材，常与干姜配伍使用。','[{\"name\": \"gaoliangjiang1.jpg\", \"path\": \"images/plants/gaoliangjiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"gaoliangjiang2.jpg\", \"path\": \"images/plants/gaoliangjiang2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"高良姜 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/高良姜 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"广东徐闻\",\"海南万宁\",\"广西防城\"]','medium','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682050, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：高良姜\", \"operator\": \"系统\"}]'),(51,'花椒','Huax jiaol','Zanthoxylum bungeanum','果实类','内服','生于山坡、路旁、灌丛中，海拔200-2500米','温中止痛，杀虫止痒。用于脘腹冷痛，呕吐泄泻，虫积腹痛，蛔虫症，湿疹瘙痒。','花椒是侗族民间最常见的调料和药材。侗家人常用花椒调味，也用它治疗脘腹冷痛。传说古时侗寨有人腹痛，服用花椒后症状缓解。花椒也是侗族治疗湿疹的常用药。','[{\"name\": \"huajiao1.jpg\", \"path\": \"images/plants/huajiao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"huajiao2.jpg\", \"path\": \"images/plants/huajiao2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"花椒的功效与作用.mp4\", \"path\": \"videos/plants/花椒的功效与作用.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"陕西韩城\",\"贵州黔东南\",\"四川汉源\"]','easy','2026-03-04 04:47:10',1,0,1,'[{\"id\": 1773145682051, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：花椒\", \"operator\": \"系统\"}]'),(52,'胡椒','Hux jiaol','Piper nigrum','果实类','内服','原产东南亚，现我国海南、广东、广西有栽培','温中散寒，下气，消痰。用于胃寒呕吐，腹痛泄泻，食欲不振，癫痫痰多。','胡椒是侗族民间常用的调料和药材。侗家人常用胡椒调味，也用它治疗胃寒呕吐。传说古时侗寨有人胃寒呕吐，服用胡椒后症状缓解。胡椒也是侗族治疗癫痫的辅助药材。','[{\"name\": \"hujiao1.jpg\", \"path\": \"images/plants/hujiao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"hujiao2.jpg\", \"path\": \"images/plants/hujiao2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"中药-胡椒.mp4\", \"path\": \"videos/plants/中药-胡椒.mp4\", \"size\": 0, \"type\": \"video\"}, {\"name\": \"中药-胡椒.mp4\", \"path\": \"videos/plants/中药-胡椒.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"海南万宁\",\"广东湛江\",\"广西防城\"]','easy','2026-03-04 04:47:10',3,0,1,'[{\"id\": 1773145682052, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：胡椒\", \"operator\": \"系统\"}]'),(53,'延胡索','Yanc huf suox','Corydalis yanhusuo','根茎类','内服','生于山地林下、灌丛中，海拔100-2000米','活血，行气，止痛。用于胸胁、脘腹疼痛，胸痹心痛，经闭痛经，产后瘀阻，跌扑肿痛。','延胡索是侗医治疗疼痛的特效药。传说古时侗寨有人胸胁疼痛，服用延胡索后疼痛消失。延胡索是侗族活血止痛的重要药材，被誉为\"止痛圣药\"。','[{\"name\": \"yanhusuo1.jpg\", \"path\": \"images/plants/yanhusuo1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yanhusuo2.jpg\", \"path\": \"images/plants/yanhusuo2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"每天学习认识一味中药材——延胡索.mp4\", \"path\": \"videos/plants/每天学习认识一味中药材——延胡索.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"浙江东阳\",\"贵州黔东南\",\"四川都江堰\"]','medium','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682053, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：延胡索\", \"operator\": \"系统\"}]'),(54,'郁金','Yuv jinl','Curcuma aromatica','根茎类','内服','生于山坡、林下、灌丛中，海拔100-2000米','活血止痛，行气解郁，清心凉血，利胆退黄。用于胸胁刺痛，胸痹心痛，经闭痛经，乳房胀痛，热病神昏，癫痫发狂，血热吐衄，黄疸尿赤。','郁金是侗医治疗黄疸的常用药。传说古时侗寨有人患黄疸，服用郁金后黄疸消退。郁金也是侗族治疗胸胁疼痛的重要药材，具有活血行气的功效。','[{\"name\": \"yujin1.jpg\", \"path\": \"images/plants/yujin1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yujin2.jpg\", \"path\": \"images/plants/yujin2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"中药精讲——郁金，带药量的中药应用讲解。.mp4\", \"path\": \"videos/plants/中药精讲——郁金，带药量的中药应用讲解。.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"浙江瑞安\",\"贵州黔东南\",\"四川双流\"]','medium','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682054, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：郁金\", \"operator\": \"系统\"}]'),(55,'姜黄','Jiangl wangc','Curcuma longa','根茎类','内服','生于向阳山坡、林下，海拔100-1500米','破血行气，通经止痛。用于胸胁刺痛，胸痹心痛，痛经经闭，癥瘕，风湿肩臂疼痛，跌扑肿痛。','姜黄是侗族民间常用的活血药。侗家人常用姜黄作为调料，也用它治疗胸胁疼痛。传说古时侗寨有人跌打损伤，服用姜黄后瘀血消散。姜黄也是侗族治疗风湿的重要药材。','[{\"name\": \"jianghuang1.jpg\", \"path\": \"images/plants/jianghuang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"jianghuang2.jpg\", \"path\": \"images/plants/jianghuang2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"姜黄 一种传统古老的着色原料，也是药食同源的一种药材.mp4\", \"path\": \"videos/plants/姜黄 一种传统古老的着色原料，也是药食同源的一种药材.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"四川犍为\",\"贵州黔东南\",\"广东佛山\"]','easy','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682055, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：姜黄\", \"operator\": \"系统\"}]'),(56,'乳香','Rux xangl','Boswellia carterii','树脂类','内服','产于索马里、埃塞俄比亚等地','活血定痛，消肿生肌。用于胸痹心痛，胃脘疼痛，痛经经闭，产后瘀阻，癥瘕腹痛，风湿痹痛，筋脉拘挛，跌打损伤，痈肿疮疡。','乳香是侗医治疗跌打损伤的常用药。传说古时侗寨有人跌打损伤，疼痛难忍。侗族药师用乳香配伍其他药物，患者服用后疼痛缓解。乳香也是侗族治疗风湿痹痛的重要药材。','[{\"name\": \"ruxiang1.jpg\", \"path\": \"images/plants/ruxiang1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"ruxiang2.jpg\", \"path\": \"images/plants/ruxiang2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"乳香 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/乳香 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"进口药材\",\"广东广州\",\"广西南宁\"]','hard','2026-03-04 04:47:10',3,1,1,'[{\"id\": 1773145682056, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：乳香\", \"operator\": \"系统\"}]'),(57,'没药','Moc yaoc','Commiphora myrrha','树脂类','内服','产于索马里、埃塞俄比亚等地','散瘀定痛，消肿生肌。用于胸痹心痛，胃脘疼痛，痛经经闭，产后瘀阻，癥瘕腹痛，风湿痹痛，筋脉拘挛，跌打损伤，痈肿疮疡。','没药是侗医治疗跌打损伤的常用药。传说古时侗寨有人跌打损伤，瘀血肿痛。侗族药师用没药配伍其他药物，患者服用后瘀血消散。没药常与乳香配伍使用，是侗族活血止痛的经典组合。','[{\"name\": \"moyao1.jpg\", \"path\": \"images/plants/moyao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"moyao2.jpg\", \"path\": \"images/plants/moyao2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"没药 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/没药 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"进口药材\",\"广东广州\",\"广西南宁\"]','hard','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682057, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：没药\", \"operator\": \"系统\"}]'),(58,'丹参','Danl senl','Salvia miltiorrhiza','根茎类','内服','生于山坡、林下、溪边，海拔120-1300米','活血祛瘀，通经止痛，清心除烦，凉血消痈。用于胸痹心痛，脘腹胁痛，癥瘕积聚，热痹疼痛，心烦不眠，月经不调，痛经经闭，疮疡肿痛。','丹参是侗医治疗胸痹的常用药。传说古时侗寨有人胸痹心痛，服用丹参后症状缓解。丹参也是侗族治疗妇科疾病的重要药材，具有活血调经的功效。','[{\"name\": \"danshen1.jpg\", \"path\": \"images/plants/danshen1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"danshen2.jpg\", \"path\": \"images/plants/danshen2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"丹参.mp4\", \"path\": \"videos/plants/丹参.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"山东平邑\",\"贵州黔东南\",\"四川中江\"]','medium','2026-03-04 04:47:10',8,0,1,'[{\"id\": 1773145682058, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：丹参\", \"operator\": \"系统\"}]'),(59,'红花','Hongc faix','Carthamus tinctorius','花类','内服','栽培于向阳、干燥的环境','活血通经，散瘀止痛。用于经闭，痛经，恶露不行，癥瘕痞块，胸痹心痛，瘀滞腹痛，胸胁刺痛，跌扑损伤，疮疡肿痛。','红花是侗族民间常用的活血药。侗家人常用红花治疗妇科疾病。传说古时侗寨有人痛经，服用红花后症状缓解。红花也是侗族治疗跌打损伤的重要药材。','[{\"name\": \"honghua1.jpg\", \"path\": \"images/plants/honghua1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"honghua2.jpg\", \"path\": \"images/plants/honghua2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"【百草故事】活血化瘀良药——红花.mp4\", \"path\": \"videos/plants/【百草故事】活血化瘀良药——红花.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"新疆塔城\",\"贵州黔东南\",\"河南新乡\"]','easy','2026-03-04 04:47:10',3,0,1,'[{\"id\": 1773145682059, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：红花\", \"operator\": \"系统\"}]'),(60,'桃仁','Taoc renl','Prunus persica','种子类','内服','栽培于平原、丘陵地区','活血祛瘀，润肠通便，止咳平喘。用于经闭痛经，癥瘕痞块，肺痈肠痈，跌打损伤，肠燥便秘，咳嗽气喘。','桃仁是侗族民间常用的活血药。侗家人常用桃仁治疗妇科疾病。传说古时侗寨有人肠燥便秘，服用桃仁后症状缓解。桃仁也是侗族治疗跌打损伤的重要药材。','[{\"name\": \"taoren1.jpg\", \"path\": \"images/plants/taoren1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"taoren2.jpg\", \"path\": \"images/plants/taoren2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"桃仁 深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/桃仁 深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"山东泰安\",\"贵州黔东南\",\"河北赞皇\"]','easy','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682060, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：桃仁\", \"operator\": \"系统\"}]'),(61,'益母草','Yiv mux caox','Leonurus japonicus','全草类','内服','生于路旁、田边、荒地，分布极广','活血调经，利尿消肿，清热解毒。用于月经不调，痛经经闭，恶露不尽，水肿尿少，疮疡肿毒。','益母草是侗族妇女的常用药。传说古时侗寨一位妇女月经不调，服用益母草后症状改善。益母草是侗族治疗妇科疾病的重要药材，被誉为\"妇科圣药\"。','[{\"name\": \"yimucao1.jpg\", \"path\": \"images/plants/yimucao1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"yimucao2.jpg\", \"path\": \"images/plants/yimucao2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"中药精讲：益母草.mp4\", \"path\": \"videos/plants/中药精讲：益母草.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"贵州黔东南\",\"河南禹州\",\"安徽亳州\"]','easy','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682061, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：益母草\", \"operator\": \"系统\"}]'),(62,'牛膝','Niuc xil','Achyranthes bidentata','根茎类','内服','生于山坡林下、灌丛中，海拔200-1700米','逐瘀通经，补肝肾，强筋骨，利尿通淋，引血下行。用于经闭，痛经，腰膝酸痛，筋骨无力，淋证，水肿，头痛，眩晕，牙痛，口疮，吐血，衄血。','牛膝是侗医治疗腰膝酸痛的常用药。传说古时侗寨有人腰膝酸痛，服用牛膝后症状缓解。牛膝也是侗族治疗妇科疾病的重要药材，具有逐瘀通经的功效。','[{\"name\": \"niuxi1.jpg\", \"path\": \"images/plants/niuxi1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"niuxi2.jpg\", \"path\": \"images/plants/niuxi2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"牛膝（怀牛膝）深度解读 教你一些你能用到的知识.mp4\", \"path\": \"videos/plants/牛膝（怀牛膝）深度解读 教你一些你能用到的知识.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"河南武陟\",\"贵州黔东南\",\"河北安国\"]','medium','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682062, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：牛膝\", \"operator\": \"系统\"}]'),(63,'鸡血藤','Jix xeeb tongc','Spatholobus suberectus','藤本类','内服','生于山谷林下、灌丛中，攀援于树上','活血补血，调经止痛，舒筋活络。用于月经不调，痛经，经闭，血虚萎黄，麻木瘫痪，风湿痹痛。','鸡血藤是侗族妇女的常用药。传说古时侗寨一位妇女月经不调，服用鸡血藤后症状改善。鸡血藤是侗族治疗妇科疾病的重要药材，也是补血活血的佳品。','[{\"name\": \"jixueteng1.jpg\", \"path\": \"images/plants/jixueteng1.jpg\", \"size\": 0, \"type\": \"image\"}, {\"name\": \"jixueteng2.jpg\", \"path\": \"images/plants/jixueteng2.jpg\", \"size\": 0, \"type\": \"image\"}]','[{\"name\": \"中药精讲：鸡血藤.mp4\", \"path\": \"videos/plants/中药精讲：鸡血藤.mp4\", \"size\": 0, \"type\": \"video\"}]',NULL,'[\"广西百色\",\"贵州黔东南\",\"云南文山\"]','medium','2026-03-04 04:47:10',2,0,1,'[{\"id\": 1773145682063, \"time\": \"2026-03-04\", \"content\": \"创建药用植物：鸡血藤\", \"operator\": \"系统\"}]');
