INSERT INTO `qa` (`id`, `category`, `question`, `answer`, `popularity`, `created_at`, `view_count`, `favorite_count`) VALUES (1,'侗药常识','什么是侗族医药？','侗族医药是侗族人民在长期的生产生活实践中，与疾病斗争中积累的医药知识和经验的总和。侗族医药具有鲜明的民族特色和地域特色，是中华民族传统医药的重要组成部分。侗族医药以草药为主，结合药浴、艾灸、推拿、拔罐等外治疗法，形成了独特的诊疗体系。',256,'2026-03-04 04:47:10',27,2),(2,'侗药常识','侗族医药有哪些特点？','侗族医药具有以下特点：1.以草药为主，善用药浴、艾灸等外治疗法；2.注重整体观念，强调人与自然的和谐统一；3.诊疗方法独特，有望、闻、问、切四诊；4.药物来源广泛，多采用当地野生药材；5.传承方式以口传心授为主；6.具有鲜明的民族文化和地域特色。',238,'2026-03-04 04:47:10',3,2),(3,'侗药常识','侗族常用的药材有哪些？','侗族常用药材包括：钩藤（清热平肝）、透骨草（祛风除湿）、九节茶（活血消斑）、八角莲（清热解毒）、七叶一枝花（消肿止痛）、血藤（补血活血）、杜仲（补肝肾）、黄精（补气养阴）、金银花（清热解毒）、艾叶（温经止血）等。这些药材多生长在侗族聚居区，是侗医临床常用的道地药材。',245,'2026-03-04 04:47:10',7,0),(4,'侗药常识','侗族药浴有什么功效？','侗族药浴具有以下功效：1.祛风除湿，治疗风湿痹痛；2.活血化瘀，促进血液循环；3.舒筋活络，缓解肌肉酸痛；4.清热解毒，治疗皮肤病；5.养生保健，增强体质。侗族药浴是侗族传统疗法的重要组成部分，通过药物煎汤浸泡全身或局部，达到防治疾病的目的。',267,'2026-03-04 04:47:10',2,1),(5,'侗医疗法','侗族艾灸疗法如何操作？','侗族艾灸疗法的操作步骤：1.选取穴位：根据病情选择相应穴位，如关元、气海、三阴交等；2.准备艾条：将艾叶制成艾条或艾柱；3.点燃艾条：点燃艾条一端；4.熏灼穴位：将艾条对准穴位，距离皮肤2-3cm，以患者感觉温热舒适为度；5.控制时间：每次15-20分钟；6.注意事项：防止烫伤，灸后保暖。',198,'2026-03-04 04:47:10',1,0),(6,'侗医疗法','侗族推拿疗法有哪些手法？','侗族推拿疗法常用的手法包括：1.推法：用指腹或掌根沿经络方向推动；2.拿法：用拇指和食指捏拿肌肉；3.按法：用指腹或掌根按压穴位；4.摩法：用手掌在体表做环形摩擦；5.揉法：用指腹或掌根做环形揉动；6.捏法：用拇指和食指捏起皮肤。这些手法可单独使用，也可配合使用。',187,'2026-03-04 04:47:10',0,0),(7,'侗医疗法','侗族如何治疗风湿骨痛？','侗族治疗风湿骨痛的方法：1.药浴疗法：用透骨草、艾叶、钩藤等药物煎汤浸泡；2.艾灸疗法：艾灸患处及相关穴位；3.推拿疗法：运用推、拿、按、摩等手法治疗；4.内服药物：服用九节茶、血藤、杜仲等药物；5.拔罐疗法：在患处拔罐祛风除湿；6.熏蒸疗法：用药物蒸汽熏蒸患处。多种方法配合使用效果更佳。',223,'2026-03-04 04:47:10',0,0),(8,'侗医疗法','侗族如何治疗跌打损伤？','侗族治疗跌打损伤的方法：1.外敷药物：用透骨草、八角莲、七叶一枝花等捣烂外敷；2.内服药物：服用活血化瘀的药物；3.推拿疗法：运用推拿手法舒筋活络；4.拔罐疗法：在患处拔罐活血化瘀；5.药浴疗法：用药物煎汤浸泡患处；6.正骨手法：对骨折脱臼进行复位。严重者需及时就医。',212,'2026-03-04 04:47:10',0,0),(9,'侗医疗法','侗族如何治疗妇科疾病？','侗族治疗妇科疾病的方法：1.艾灸疗法：艾灸关元、气海、三阴交等穴位；2.药浴疗法：用艾叶、血藤等药物煎汤坐浴；3.内服药物：服用血藤、艾叶、杜仲等药物；4.熏蒸疗法：用药物蒸汽熏蒸；5.推拿疗法：运用推拿手法调理气血；6.食疗调理：配合药膳食疗。侗族妇科疗法对产后调理、月经不调有显著疗效。',201,'2026-03-04 04:47:10',0,0),(10,'侗医疗法','侗族如何治疗小儿疾病？','侗族治疗小儿疾病的方法：1.小儿推拿：运用推、揉、捏、拿等手法作用于特定穴位；2.药浴疗法：用温和药物煎汤洗浴；3.敷贴疗法：将药物敷贴于特定部位；4.内服药物：服用温和的药物煎剂；5.食疗调理：配合食疗调理脾胃；6.艾灸疗法：艾灸特定穴位。侗族儿科疗法对小儿发热、咳嗽、消化不良有良好疗效。',195,'2026-03-04 04:47:10',0,0),(11,'文化背景','侗族医药的历史渊源是什么？','侗族医药历史悠久，起源可追溯到侗族先民的原始医疗活动。侗族先民在长期的生产生活中，通过观察动物自救行为、尝试各种植物，逐渐积累了医药知识。经过代代相传，形成了独特的侗族医药体系。侗族医药与侗族的宗教信仰、生活习俗密切相关，是侗族文化的重要组成部分。',178,'2026-03-04 04:47:10',0,0),(12,'文化背景','侗族医药如何传承？','侗族医药的传承方式主要有：1.家族传承：父传子、母传女，代代相传；2.师徒传承：拜师学艺，口传心授；3.社区传承：在侗族社区中通过实践学习；4.文献传承：通过侗族古歌、传说等形式传承医药知识。近年来，政府大力支持侗族医药的传承发展，建立了传承人制度，开设了侗医药培训班，使侗族医药得到更好的保护和传承。',186,'2026-03-04 04:47:10',0,0),(13,'文化背景','侗族医药有哪些文化内涵？','侗族医药蕴含丰富的文化内涵：1.天人合一的整体观念；2.阴阳平衡的哲学思想；3.预防为主的养生理念；4.药食同源的饮食文化；5.敬畏自然的生态意识；6.团结互助的社区精神。侗族医药不仅是一种医疗技术，更是侗族文化的重要载体，体现了侗族人民的智慧和哲学思想。',169,'2026-03-04 04:47:10',0,0),(14,'文化背景','侗族医药的现状如何？','目前侗族医药面临机遇与挑战并存的局面。机遇方面：国家大力支持民族医药发展，侗族医药被列入非物质文化遗产保护名录，传承人得到认定和资助。挑战方面：年轻一代对侗族医药兴趣不足，传承人老龄化严重，部分传统疗法面临失传风险。需要加强保护传承，推动侗族医药创新发展。',172,'2026-03-04 04:47:10',0,0),(15,'文化背景','如何学习和了解侗族医药？','学习和了解侗族医药的途径：1.阅读侗族医药相关书籍和文献；2.参观侗族医药博物馆和文化展览；3.参加侗族医药培训班和讲座；4.拜访侗族医药传承人，拜师学艺；5.深入侗族地区，实地考察学习；6.关注侗族医药相关的网站和公众号。建议从基础知识学起，循序渐进，理论与实践相结合。',165,'2026-03-04 04:47:10',0,0),(16,'侗药常识','侗族药材如何采集和炮制？','侗族药材采集讲究时节和方法：1.根茎类药材多在秋冬季节采集；2.全草类药材多在花期采集；3.花叶类药材多在春夏采集；4.果实类药材在成熟时采集。炮制方法包括：晒干、阴干、炒制、蒸制、酒制、醋制等。侗族认为正确的采集和炮制方法能保证药材质量，提高疗效。',189,'2026-03-04 04:47:10',0,0),(17,'侗医疗法','侗族拔罐疗法如何操作？','侗族拔罐疗法的操作步骤：1.患者取舒适体位，暴露治疗部位；2.选择拔罐部位，清洁皮肤；3.准备竹罐或玻璃罐；4.用火燃烧法或抽气法产生负压；5.将罐吸附于皮肤上；6.留罐10-15分钟；7.取罐时先按压皮肤，使空气进入，再取下罐子。注意：皮肤破损、孕妇腹部不宜拔罐。',176,'2026-03-04 04:47:10',0,0),(18,'侗医疗法','侗族熏蒸疗法如何操作？','侗族熏蒸疗法的操作步骤：1.准备药物：艾叶、透骨草、钩藤等；2.加水煎煮，产生蒸汽；3.患者取坐位或卧位，暴露治疗部位；4.用蒸汽熏蒸患处，距离以患者感觉温热舒适为度；5.每次熏蒸20-30分钟；6.熏蒸后擦干保暖。注意：防止烫伤，心脏病患者慎用。',182,'2026-03-04 04:47:10',0,0),(19,'侗药常识','侗族药材如何保存？','侗族药材保存方法：1.干燥保存：将药材晒干或阴干，置于干燥通风处；2.密封保存：将干燥药材装入密封容器，防止受潮；3.防虫保存：在药材中放入花椒、大蒜等防虫；4.冷藏保存：部分鲜药可冷藏保存；5.定期检查：定期检查药材，发现霉变及时处理。正确的保存方法能保证药材质量，延长保存期限。',168,'2026-03-04 04:47:10',0,0),(20,'文化背景','侗族医药与现代医学如何结合？','侗族医药与现代医学结合的方式：1.运用现代科技研究侗族药材的有效成分；2.用现代医学理论解释侗族医药的作用机理；3.将侗族传统疗法与现代诊疗技术相结合；4.开发侗族医药新产品，如侗药制剂、保健品等；5.建立侗族医药与现代医学结合的诊疗模式。这种结合既能传承侗族医药精华，又能提高诊疗效果。',175,'2026-03-04 04:47:10',0,0),(21,'侗药常识','钩藤有什么功效和用途？','钩藤具有清热平肝、息风定惊的功效。主要用于治疗：1.头痛眩晕；2.感冒夹惊；3.惊痫抽搐；4.妊娠子痫；5.高血压引起的头晕头痛。侗族民间常用钩藤治疗小儿惊风，效果显著。用法：煎汤内服，常用量10-15g。注意事项：不宜久煎，一般后下。',198,'2026-03-04 04:47:10',0,0),(22,'侗药常识','透骨草有什么功效和用途？','透骨草具有祛风除湿、舒筋活血、止痛的功效。主要用于治疗：1.风湿痹痛；2.筋骨挛缩；3.寒湿脚气；4.疮癣肿毒；5.跌打损伤。侗族民间常用透骨草治疗跌打损伤和风湿疼痛，可内服也可外用。用法：煎汤内服或捣烂外敷，常用量15-30g。',185,'2026-03-04 04:47:10',0,0),(23,'侗药常识','八角莲有什么功效和用途？','八角莲具有清热解毒、化痰散结、祛瘀消肿的功效。主要用于治疗：1.痈肿疔疮；2.瘰疬；3.咽喉肿痛；4.跌打损伤；5.毒蛇咬伤。八角莲是侗医治疗毒蛇咬伤的要药，被誉为\"蛇伤圣药\"。用法：煎汤内服或捣烂外敷。注意：八角莲有毒，需在医师指导下使用。',192,'2026-03-04 04:47:10',0,0),(24,'侗药常识','天麻有什么功效和用途？','天麻具有息风止痉、平抑肝阳、祛风通络的功效。主要用于治疗：1.肝风内动，惊痫抽搐；2.眩晕头痛；3.肢体麻木；4.手足不遂；5.风湿痹痛。天麻是贵州道地药材，侗族民间常用天麻治疗头晕头痛。用法：煎汤内服或研末冲服，常用量3-10g。',178,'2026-03-04 04:47:10',0,0),(25,'侗药常识','金银花有什么功效和用途？','金银花具有清热解毒、疏散风热的功效。主要用于治疗：1.痈肿疔疮；2.喉痹；3.丹毒；4.热毒血痢；5.风热感冒；6.温病发热。金银花是侗族民间常用的清热解毒药，每年春夏之交采摘晒干备用。用法：煎汤内服或泡茶饮用，常用量10-30g。',186,'2026-03-04 04:47:10',0,0),(26,'侗药常识','艾叶有什么功效和用途？','艾叶具有温经止血、散寒止痛、祛湿止痒的功效。主要用于治疗：1.吐血、衄血、崩漏；2.月经过多；3.胎漏下血；4.少腹冷痛；5.经寒不调；6.宫冷不孕。艾叶是侗族艾灸疗法的主要材料，也是药浴的重要药材。用法：煎汤内服、外用熏洗或艾灸，常用量3-10g。',195,'2026-03-04 04:47:10',0,0),(27,'侗药常识','杜仲有什么功效和用途？','杜仲具有补肝肾、强筋骨、安胎的功效。主要用于治疗：1.肾虚腰痛；2.筋骨无力；3.妊娠漏血；4.胎动不安；5.高血压。杜仲是贵州道地药材，侗族民间常用杜仲治疗腰膝酸痛。用法：煎汤内服或泡酒服用，常用量6-10g。',168,'2026-03-04 04:47:10',0,0),(28,'侗药常识','黄精有什么功效和用途？','黄精具有补气养阴、健脾、润肺、益肾的功效。主要用于治疗：1.脾胃气虚，体倦乏力；2.胃阴不足，口干食少；3.肺虚燥咳；4.精血不足，腰膝酸软。黄精是侗族常用的滋补药，也是侗族食疗的重要材料。用法：煎汤内服或煲汤食用，常用量9-15g。',172,'2026-03-04 04:47:10',0,0),(29,'侗药常识','血藤有什么功效和用途？','血藤具有补血、活血、通络的功效。主要用于治疗：1.月经不调；2.血虚萎黄；3.麻木瘫痪；4.风湿痹痛。血藤是侗族妇女的常用药，侗族民间常用血藤治疗妇科疾病和风湿疼痛。用法：煎汤内服或泡酒服用，常用量10-30g。',165,'2026-03-04 04:47:10',0,0),(30,'侗医疗法','侗族药浴疗法有什么禁忌？','侗族药浴疗法的禁忌：1.孕妇慎用，部分药材可能影响胎儿；2.月经期妇女不宜全身药浴；3.严重心脏病、高血压患者慎用；4.皮肤破损、溃烂处不宜药浴；5.饭后不宜立即药浴，应间隔1-2小时；6.药浴时间不宜过长，一般20-30分钟；7.药浴后应及时擦干保暖，避免受凉。',188,'2026-03-04 04:47:10',0,0),(31,'侗医疗法','侗族艾灸疗法有什么禁忌？','侗族艾灸疗法的禁忌：1.孕妇腹部、腰骶部不宜艾灸；2.高热患者不宜艾灸；3.皮肤破损、溃烂处不宜艾灸；4.阴虚火旺者慎用；5.大血管处、心脏部位不宜艾灸；6.艾灸后不宜立即洗澡，应间隔2-3小时；7.艾灸时应注意防止烫伤，保持适当距离。',176,'2026-03-04 04:47:10',0,0),(32,'侗医疗法','侗族推拿疗法有什么禁忌？','侗族推拿疗法的禁忌：1.急性传染病、高热患者不宜推拿；2.皮肤破损、溃烂处不宜推拿；3.骨折、脱臼未复位者不宜推拿；4.孕妇腹部、腰骶部不宜推拿；5.严重心脏病、高血压患者慎用；6.饭后不宜立即推拿，应间隔1-2小时；7.推拿力度应适中，不宜过重。',169,'2026-03-04 04:47:10',0,0),(33,'侗医疗法','侗族拔罐疗法有什么禁忌？','侗族拔罐疗法的禁忌：1.孕妇腹部、腰骶部不宜拔罐；2.皮肤破损、溃烂处不宜拔罐；3.高热患者不宜拔罐；4.严重心脏病、高血压患者慎用；5.有出血倾向者不宜拔罐；6.拔罐时间不宜过长，一般10-15分钟；7.拔罐后不宜立即洗澡，应间隔2-3小时。',172,'2026-03-04 04:47:10',0,0),(34,'侗医疗法','侗族熏蒸疗法有什么禁忌？','侗族熏蒸疗法的禁忌：1.孕妇慎用，高温可能影响胎儿；2.严重心脏病、高血压患者慎用；3.高热患者不宜熏蒸；4.皮肤破损、溃烂处不宜熏蒸；5.熏蒸时间不宜过长，一般20-30分钟；6.熏蒸时应注意防止烫伤，保持适当距离；7.熏蒸后应及时擦干保暖，避免受凉。',165,'2026-03-04 04:47:10',0,0),(35,'侗医疗法','侗族如何治疗感冒？','侗族治疗感冒的方法：1.内服药物：服用金银花、鱼腥草、车前草等清热解毒药物；2.药浴疗法：用艾叶、金银花等药物煎汤洗浴；3.刮痧疗法：刮拭背部经络祛风解表；4.艾灸疗法：艾灸大椎、风池等穴位；5.食疗调理：多饮温水，食用清淡易消化食物；6.注意休息，避免过度劳累。',198,'2026-03-04 04:47:10',0,0),(36,'侗医疗法','侗族如何治疗咳嗽？','侗族治疗咳嗽的方法：1.内服药物：服用半夏、茯苓、鱼腥草等化痰止咳药物；2.药浴疗法：用艾叶、金银花等药物煎汤熏蒸；3.艾灸疗法：艾灸肺俞、定喘等穴位；4.推拿疗法：推拿胸部和背部经络；5.食疗调理：食用梨、蜂蜜等润肺食物；6.注意保暖，避免受凉。',186,'2026-03-04 04:47:10',0,0),(37,'侗医疗法','侗族如何治疗胃痛？','侗族治疗胃痛的方法：1.内服药物：服用吴茱萸、高良姜、陈皮等温胃止痛药物；2.艾灸疗法：艾灸中脘、足三里等穴位；3.推拿疗法：推拿腹部经络；4.药浴疗法：用艾叶、吴茱萸等药物煎汤熏蒸；5.食疗调理：少食多餐，忌食生冷油腻；6.保持心情舒畅，避免过度劳累。',178,'2026-03-04 04:47:10',0,0),(38,'侗医疗法','侗族如何治疗失眠？','侗族治疗失眠的方法：1.内服药物：服用茯苓、何首乌、天麻等养心安神药物；2.艾灸疗法：艾灸神门、三阴交等穴位；3.推拿疗法：推拿头部和背部经络；4.药浴疗法：用艾叶、茯苓等药物煎汤泡脚；5.食疗调理：睡前饮用温牛奶或蜂蜜水；6.保持心情舒畅，睡前避免剧烈活动。',168,'2026-03-04 04:47:10',0,0),(39,'侗医疗法','侗族如何治疗高血压？','侗族治疗高血压的方法：1.内服药物：服用钩藤、天麻、菊花等平肝降压药物；2.药浴疗法：用钩藤、菊花等药物煎汤泡脚；3.艾灸疗法：艾灸足三里、太冲等穴位；4.推拿疗法：推拿头部和背部经络；5.食疗调理：低盐饮食，多食蔬菜水果；6.保持心情舒畅，定期监测血压。',175,'2026-03-04 04:47:10',0,0),(40,'文化背景','侗族医药的哲学思想是什么？','侗族医药的哲学思想包括：1.天人合一的整体观念：认为人与自然是一个整体，疾病的发生与自然环境密切相关；2.阴阳平衡的哲学思想：认为人体健康取决于阴阳平衡，疾病是阴阳失调的表现；3.预防为主的养生理念：强调\"治未病\"，注重养生保健；4.药食同源的饮食文化：认为食物和药物同源，食疗是治病养生的重要方法。',182,'2026-03-04 04:47:10',0,0),(41,'文化背景','侗族医药与中医有什么区别？','侗族医药与中医的区别：1.理论体系：中医有完整的理论体系，侗族医药理论相对朴素；2.诊断方法：中医有四诊八纲，侗医有望闻问切；3.治疗方法：中医方法多样，侗医以外治法见长；4.药物来源：中医用药广泛，侗医多用当地野生药材；5.传承方式：中医有系统的教育体系，侗医以口传心授为主；6.文化背景：中医受儒家文化影响，侗医受侗族文化影响。',168,'2026-03-04 04:47:10',0,0),(42,'文化背景','侗族医药的保护措施有哪些？','侗族医药的保护措施：1.列入非物质文化遗产保护名录；2.认定和保护传承人；3.建立侗族医药博物馆和文化展览馆；4.开展侗族医药培训和教育活动；5.整理出版侗族医药文献资料；6.支持侗族医药科研和开发；7.建立侗族医药保护区和种植基地。这些措施有助于保护和传承侗族医药文化。',175,'2026-03-04 04:47:10',0,0),(43,'文化背景','侗族医药的发展前景如何？','侗族医药的发展前景广阔：1.国家政策支持民族医药发展；2.人们对传统医药的需求增加；3.现代科技为侗族医药研究提供新方法；4.侗族医药产业化发展潜力巨大；5.侗族医药文化旅游兴起；6.国际社会对传统医药的关注度提高。同时，侗族医药也面临传承人老龄化、年轻一代兴趣不足等挑战，需要加强保护和传承。',172,'2026-03-04 04:47:10',0,0),(44,'侗药常识','侗族药材如何鉴别真伪？','侗族药材鉴别真伪的方法：1.外观鉴别：观察药材的形状、大小、颜色、质地等特征；2.气味鉴别：闻药材的气味，真品有特殊香气；3.味道鉴别：尝药材的味道，真品有特定味道；4.水试鉴别：将药材放入水中观察变化；5.火试鉴别：用火烧药材观察变化；6.经验鉴别：传承人的经验判断。建议到正规渠道购买药材，避免购买假冒伪劣产品。',168,'2026-03-04 04:47:10',0,0),(45,'侗药常识','侗族药材如何配伍使用？','侗族药材配伍使用的原则：1.君臣佐使：主药为君，辅药为臣，佐药为佐，引药为使；2.相须相使：性能相似的药物配伍可增强疗效；3.相畏相杀：一种药物可减轻另一种药物的毒性；4.相反相恶：某些药物配伍会产生不良反应，应避免；5.剂量配比：根据病情和药物性能确定剂量配比。侗族药师在长期实践中积累了丰富的配伍经验。',175,'2026-03-04 04:47:10',0,0),(46,'侗药常识','侗族药材有哪些常用剂型？','侗族药材常用剂型：1.汤剂：将药物加水煎煮，取汁服用；2.散剂：将药物研成粉末，冲服或外敷；3.丸剂：将药物粉末加蜜或水制成丸剂；4.酒剂：将药物浸泡在白酒中，取酒服用；5.膏剂：将药物煎熬浓缩成膏；6.熏蒸剂：将药物加水煎煮，用蒸汽熏蒸；7.药浴剂：将药物加水煎煮，用于洗浴。不同剂型适用于不同病症。',168,'2026-03-04 04:47:10',0,0),(47,'侗药常识','侗族药材的用量如何确定？','侗族药材用量的确定原则：1.根据药物性能：毒性大的药物用量小，毒性小的药物用量大；2.根据病情轻重：病情重用量大，病情轻用量小；3.根据患者体质：体质强者用量可大，体质弱者用量宜小；4.根据患者年龄：成人用量大，儿童用量小；5.根据配伍关系：单味药用量大，复方中用量小；6.根据季节气候：夏季用量宜小，冬季用量可大。侗族药师在长期实践中积累了丰富的用量经验。',165,'2026-03-04 04:47:10',0,0),(48,'侗药常识','侗族药材有哪些注意事项？','侗族药材使用的注意事项：1.辨证用药：根据病情选择合适的药物；2.注意用量：严格按照规定用量使用，不宜过量；3.注意禁忌：孕妇、儿童、老人等特殊人群用药需谨慎；4.注意配伍：避免相反相恶的药物配伍；5.注意炮制：部分药材需炮制后使用；6.注意保存：正确保存药材，防止霉变虫蛀；7.注意疗程：按照疗程用药，不宜长期服用。建议在医师指导下使用。',172,'2026-03-04 04:47:10',0,0);
