--
-- Table structure for table `quiz_questions`
--

DROP TABLE IF EXISTS `quiz_questions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `quiz_questions` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `question` text NOT NULL COMMENT '题目内容',
  `options` text CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '选项["A","B","C","D"]',
  `answer` varchar(500) NOT NULL COMMENT '正确答案',
  `category` varchar(50) DEFAULT NULL COMMENT '题目分类',
  `difficulty` varchar(20) DEFAULT 'easy' COMMENT '难度: easy/medium/hard',
  `correct_answer` varchar(10) DEFAULT NULL COMMENT '正确选项: A/B/C/D',
  `explanation` text COMMENT '答案解析',
  PRIMARY KEY (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=50 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='测验题目表';
/*!40101 SET character_set_client = @saved_cs_client */;

