/*!40000 ALTER TABLE `quiz_questions` DISABLE KEYS */;
INSERT INTO `quiz_questions` (`id`, `question`, `options`, `answer`, `category`, `difficulty`, `correct_answer`, `explanation`) VALUES (1,'钩藤的主要功效是什么？','[\"清热平肝，息风定惊\", \"补气养血，健脾益肺\", \"滋阴补肾，益精填髓\", \"活血化瘀，通络止痛\"]','清热平肝，息风定惊','侗药常识','easy','A','钩藤具有清热平肝、息风定惊的功效，常用于治疗头痛眩晕、惊痫抽搐、妊娠子痫等症。'),(2,'侗族药浴疗法的主要功效不包括以下哪项？','[\"祛风除湿\", \"活血化瘀\", \"清热解毒\", \"滋阴补肾\"]','滋阴补肾','侗医疗法','easy','D','侗族药浴疗法主要功效包括祛风除湿、活血化瘀、舒筋活络、清热解毒等，滋阴补肾不是其主要功效。'),(3,'八角莲在侗医中主要用于治疗什么疾病？','[\"感冒发热\", \"毒蛇咬伤\", \"消化不良\", \"失眠多梦\"]','毒蛇咬伤','侗药常识','medium','B','八角莲具有清热解毒、化痰散结的功效，是侗医治疗毒蛇咬伤的要药，被誉为\"蛇伤圣药\"。'),(4,'侗族艾灸疗法常用的穴位不包括以下哪个？','[\"关元穴\", \"气海穴\", \"三阴交穴\", \"太阳穴\"]','太阳穴','侗医疗法','medium','D','侗族艾灸疗法常用穴位包括关元、气海、三阴交等，太阳穴一般不用于艾灸。'),(5,'以下哪种药材具有补血活血的功效？','[\"钩藤\", \"透骨草\", \"血藤\", \"金银花\"]','血藤','侗药常识','easy','C','血藤具有补血、活血、通络的功效，常用于治疗月经不调、血虚萎黄、风湿痹痛等症。'),(6,'侗族医药的主要传承方式是什么？','[\"学校教育\", \"书籍传承\", \"口传心授\", \"网络学习\"]','口传心授','文化背景','easy','C','侗族医药的主要传承方式是口传心授，包括家族传承、师徒传承等形式。'),(7,'天麻的主要功效是什么？','[\"清热解毒\", \"息风止痉，平抑肝阳\", \"补气养血\", \"健脾益肺\"]','息风止痉，平抑肝阳','侗药常识','medium','B','天麻具有息风止痉、平抑肝阳、祛风通络的功效，常用于治疗眩晕头痛、惊痫抽搐、肢体麻木等症。'),(8,'侗族药浴的水温一般控制在多少度？','[\"30-35℃\", \"40-45℃\", \"50-55℃\", \"60℃以上\"]','40-45℃','侗医疗法','easy','B','侗族药浴的水温一般控制在40-45℃，温度过高容易烫伤，过低则影响药效。'),(9,'以下哪种药材是侗医治疗蛇伤的要药？','[\"钩藤\", \"透骨草\", \"八角莲\", \"金银花\"]','八角莲','侗药常识','medium','C','八角莲具有清热解毒、化痰散结的功效，是侗医治疗毒蛇咬伤的要药，被誉为\"蛇伤圣药\"。'),(10,'侗族医药主要分布在哪些地区？','[\"西藏地区\", \"侗族聚居区（贵州、广西、湖南）\", \"东北地区\", \"华北地区\"]','侗族聚居区（贵州、广西、湖南）','文化背景','easy','B','侗族医药主要分布在侗族聚居区，包括贵州黔东南、广西三江、湖南通道等地。'),(11,'艾叶在侗医中的主要用途不包括？','[\"艾灸疗法\", \"药浴疗法\", \"治疗风湿\", \"治疗糖尿病\"]','治疗糖尿病','侗医疗法','medium','D','艾叶在侗医中主要用于艾灸疗法、药浴疗法、治疗风湿等，不是治疗糖尿病的主要药物。'),(12,'七叶一枝花的主要功效是什么？','[\"清热解毒，消肿止痛\", \"补气养血\", \"滋阴补肾\", \"健脾益肺\"]','清热解毒，消肿止痛','侗药常识','medium','A','七叶一枝花具有清热解毒、消肿止痛、凉肝定惊的功效，常用于治疗疔疮痈肿、蛇虫咬伤等。'),(13,'侗族医药被列入哪一级非物质文化遗产？','[\"县级\", \"市级\", \"省级\", \"国家级\"]','国家级','文化背景','easy','D','侗族医药已被列入国家级非物质文化遗产名录，是中华民族传统医药的重要组成部分。'),(14,'以下哪种药材具有清热解毒的功效？','[\"杜仲\", \"血藤\", \"金银花\", \"黄精\"]','金银花','侗药常识','easy','C','金银花具有清热解毒、疏散风热的功效，常用于治疗痈肿疔疮、喉痹、热毒血痢等症。'),(15,'侗医治疗跌打损伤常用的药材组合是？','[\"钩藤+天麻\", \"透骨草+八角莲+七叶一枝花\", \"金银花+艾叶\", \"杜仲+黄精\"]','透骨草+八角莲+七叶一枝花','侗医疗法','hard','B','侗医治疗跌打损伤常用透骨草、八角莲、七叶一枝花等药材组合，具有活血化瘀、消肿止痛的功效。'),(16,'鱼腥草在侗族地区的用途是？','[\"仅作药用\", \"仅作食用\", \"药食两用\", \"观赏植物\"]','药食两用','侗药常识','easy','C','鱼腥草在侗族地区既是常见野菜，也是清热解毒的药材，是典型的药食两用植物。'),(17,'侗族艾灸疗法的操作距离是？','[\"直接接触皮肤\", \"距离皮肤2-3cm\", \"距离皮肤10cm\", \"距离皮肤20cm\"]','距离皮肤2-3cm','侗医疗法','easy','B','侗族艾灸疗法操作时，艾条点燃后对准穴位，距离皮肤2-3cm，以患者感觉温热舒适为度。'),(18,'以下哪种药材具有祛风除湿的功效？','[\"钩藤\", \"透骨草\", \"金银花\", \"茯苓\"]','透骨草','侗药常识','easy','B','透骨草具有祛风除湿、舒筋活血、止痛的功效，常用于治疗风湿痹痛、筋骨挛缩等症。'),(19,'侗族药浴疗法的浸泡时间一般是？','[\"5-10分钟\", \"20-30分钟\", \"1小时以上\", \"2小时以上\"]','20-30分钟','侗医疗法','easy','B','侗族药浴疗法的浸泡时间一般为20-30分钟，时间过短效果不佳，过长则容易疲劳。'),(20,'何首乌的主要功效是什么？','[\"清热解毒\", \"补肝肾，益精血，乌须发\", \"祛风除湿\", \"健脾益肺\"]','补肝肾，益精血，乌须发','侗药常识','medium','B','何首乌制用具有补肝肾、益精血、乌须发的功效，生用具有解毒、消痈、润肠通便的功效。'),(21,'侗族医药的理论体系主要基于？','[\"现代医学理论\", \"中医理论+侗族民间经验\", \"西医理论\", \"印度医学理论\"]','中医理论+侗族民间经验','文化背景','medium','B','侗族医药的理论体系主要基于中医理论，结合侗族民间长期积累的医疗经验，形成了独特的民族医药体系。'),(22,'以下哪种药材适合用于药浴？','[\"钩藤\", \"艾叶\", \"天麻\", \"何首乌\"]','艾叶','侗医疗法','easy','B','艾叶是侗族药浴疗法的主要药材之一，具有温经止血、散寒止痛、祛湿止痒的功效。'),(23,'侗医治疗小儿惊风的代表方剂是？','[\"钩藤+天麻+金银花+茯苓\", \"透骨草+艾叶\", \"八角莲+七叶一枝花\", \"杜仲+黄精\"]','钩藤+天麻+金银花+茯苓','侗医疗法','hard','A','侗医治疗小儿惊风的代表方剂由钩藤、天麻、金银花、茯苓组成，具有息风止痉、清热安神的功效。'),(24,'杜仲的主要功效是什么？','[\"清热解毒\", \"补肝肾，强筋骨\", \"活血化瘀\", \"祛风除湿\"]','补肝肾，强筋骨','侗药常识','easy','B','杜仲具有补肝肾、强筋骨、安胎的功效，常用于治疗肾虚腰痛、筋骨无力等症。'),(25,'侗族医药的文化价值体现在？','[\"仅是医疗技术\", \"医疗技术+民族文化传承\", \"仅是文化展示\", \"仅是经济价值\"]','医疗技术+民族文化传承','文化背景','medium','B','侗族医药不仅是医疗技术，更是侗族文化的重要组成部分，承载着侗族人民的智慧和文化遗产。'),(26,'黄精的主要功效是什么？','[\"清热解毒\", \"补气养阴，健脾润肺\", \"活血化瘀\", \"祛风除湿\"]','补气养阴，健脾润肺','侗药常识','medium','B','黄精具有补气养阴、健脾、润肺、益肾的功效，常用于治疗脾胃气虚、体倦乏力等症。'),(27,'侗族推拿疗法的手法不包括？','[\"推法\", \"拿法\", \"针灸法\", \"揉法\"]','针灸法','侗医疗法','easy','C','侗族推拿疗法的手法包括推法、拿法、按法、摩法、揉法、捏法等，针灸法不属于推拿手法。'),(28,'茯苓的主要功效是什么？','[\"清热解毒\", \"利水渗湿，健脾宁心\", \"活血化瘀\", \"祛风除湿\"]','利水渗湿，健脾宁心','侗药常识','medium','B','茯苓具有利水渗湿、健脾、宁心的功效，常用于治疗水肿尿少、痰饮眩悸、脾虚食少等症。'),(29,'侗族拔罐疗法的留罐时间是？','[\"5分钟以下\", \"10-15分钟\", \"30分钟以上\", \"1小时以上\"]','10-15分钟','侗医疗法','easy','B','侗族拔罐疗法的留罐时间一般为10-15分钟，时间过长容易造成皮肤损伤。'),(30,'车前草的主要功效是什么？','[\"清热利尿，祛痰止咳\", \"补气养血\", \"滋阴补肾\", \"健脾益肺\"]','清热利尿，祛痰止咳','侗药常识','medium','A','车前草具有清热利尿、祛痰止咳的功效，常用于治疗水肿尿少、热淋涩痛、痰热咳嗽等症。'),(31,'侗族熏蒸疗法的温度控制是？','[\"以患者感觉温热舒适为度\", \"越热越好\", \"常温即可\", \"需要冰镇\"]','以患者感觉温热舒适为度','侗医疗法','easy','A','侗族熏蒸疗法的温度以患者感觉温热舒适为度，距离适当，防止烫伤。'),(32,'半夏的主要功效是什么？','[\"清热解毒\", \"燥湿化痰，降逆止呕\", \"活血化瘀\", \"祛风除湿\"]','燥湿化痰，降逆止呕','侗药常识','medium','B','半夏具有燥湿化痰、降逆止呕、消痞散结的功效，常用于治疗痰多咳喘、痰饮眩悸等症。'),(33,'侗族医药的\"四诊\"是指？','[\"望闻问切\", \"视触叩听\", \"望闻问切+摸\", \"望触叩听\"]','望闻问切+摸','文化背景','medium','C','侗族医药的诊断方法包括望、闻、问、切四诊，此外还有\"摸\"诊，即触诊患处。'),(34,'吴茱萸的主要功效是什么？','[\"清热解毒\", \"散寒止痛，降逆止呕\", \"活血化瘀\", \"祛风除湿\"]','散寒止痛，降逆止呕','侗药常识','medium','B','吴茱萸具有散寒止痛、降逆止呕、助阳止泻的功效，常用于治疗厥阴头痛、寒疝腹痛等症。'),(35,'侗族药浴疗法不适合的人群是？','[\"风湿病患者\", \"孕妇\", \"健康人群\", \"老年人\"]','孕妇','侗医疗法','medium','B','侗族药浴疗法不适合孕妇、月经期妇女、严重心脏病患者等人群，需谨慎使用。'),(36,'高良姜的主要功效是什么？','[\"清热解毒\", \"温胃散寒，消食止痛\", \"活血化瘀\", \"祛风除湿\"]','温胃散寒，消食止痛','侗药常识','medium','B','高良姜具有温胃散寒、消食止痛的功效，常用于治疗脘腹冷痛、胃寒呕吐等症。'),(37,'侗族医药的\"天人合一\"思想是指？','[\"人与自然和谐统一\", \"人与社会和谐统一\", \"人与他人和谐统一\", \"人与动物和谐统一\"]','人与自然和谐统一','文化背景','medium','A','侗族医药的\"天人合一\"思想认为人与自然是一个整体，疾病的发生与自然环境密切相关。'),(38,'陈皮的主要功效是什么？','[\"清热解毒\", \"理气健脾，燥湿化痰\", \"活血化瘀\", \"祛风除湿\"]','理气健脾，燥湿化痰','侗药常识','easy','B','陈皮具有理气健脾、燥湿化痰的功效，常用于治疗脘腹胀满、食少吐泻、咳嗽痰多等症。'),(39,'侗族艾灸疗法的禁忌不包括？','[\"孕妇腹部\", \"高热患者\", \"皮肤破损处\", \"健康人群\"]','健康人群','侗医疗法','easy','D','侗族艾灸疗法的禁忌包括孕妇腹部、高热患者、皮肤破损处等，健康人群可以进行艾灸保健。'),(40,'菊花的主要功效是什么？','[\"清热解毒，平肝明目\", \"补气养血\", \"滋阴补肾\", \"健脾益肺\"]','清热解毒，平肝明目','侗药常识','easy','A','菊花具有散风清热、平肝明目、清热解毒的功效，常用于治疗风热感冒、头痛眩晕等症。'),(41,'侗族医药的发展前景包括？','[\"国家政策支持\", \"传承人老龄化\", \"年轻一代兴趣不足\", \"以上都是\"]','以上都是','文化背景','medium','D','侗族医药的发展前景广阔，但也面临传承人老龄化、年轻一代兴趣不足等挑战。'),(42,'郁金的主要功效是什么？','[\"清热解毒\", \"活血止痛，行气解郁\", \"补气养血\", \"祛风除湿\"]','活血止痛，行气解郁','侗药常识','medium','B','郁金具有活血止痛、行气解郁、清心凉血、利胆退黄的功效，常用于治疗胸胁刺痛、黄疸等症。'),(43,'侗族正骨疗法主要用于治疗？','[\"感冒发热\", \"骨折脱臼\", \"消化不良\", \"失眠多梦\"]','骨折脱臼','侗医疗法','easy','B','侗族正骨疗法主要用于治疗骨折、脱臼、跌打损伤等骨伤科疾病。'),(44,'茵陈的主要功效是什么？','[\"清热解毒\", \"清利湿热，利胆退黄\", \"活血化瘀\", \"祛风除湿\"]','清利湿热，利胆退黄','侗药常识','medium','B','茵陈具有清利湿热、利胆退黄的功效，是治疗黄疸的要药，常用于治疗黄疸尿少、湿温暑湿等症。'),(45,'侗族医药的传承方式不包括？','[\"家族传承\", \"师徒传承\", \"学校教育\", \"网络传承\"]','网络传承','文化背景','easy','D','侗族医药的传统传承方式主要是家族传承和师徒传承，现代也有学校教育，网络传承不是传统方式。'),(46,'金钱草的主要功效是什么？','[\"清热解毒\", \"利湿退黄，利尿通淋\", \"活血化瘀\", \"祛风除湿\"]','利湿退黄，利尿通淋','侗药常识','medium','B','金钱草具有利湿退黄、利尿通淋、解毒消肿的功效，常用于治疗黄疸、胆胀胁痛、石淋等症。'),(47,'侗族医药与中医的主要区别是？','[\"理论体系不同\", \"传承方式不同\", \"药物来源不同\", \"以上都是\"]','以上都是','文化背景','medium','D','侗族医药与中医在理论体系、传承方式、药物来源、治疗方法等方面都有所不同。'),(48,'虎杖的主要功效是什么？','[\"清热解毒\", \"利湿退黄，清热解毒，散瘀止痛\", \"补气养血\", \"祛风除湿\"]','利湿退黄，清热解毒，散瘀止痛','侗药常识','medium','B','虎杖具有利湿退黄、清热解毒、散瘀止痛、止咳化痰的功效，常用于治疗湿热黄疸、淋浊等症。'),(49,'侗族药浴疗法的主要药材不包括？','[\"艾叶\", \"透骨草\", \"钩藤\", \"金银花\"]','金银花','侗医疗法','medium','D','侗族药浴疗法的主要药材包括艾叶、透骨草、钩藤等，金银花一般用于清热解毒，不是药浴主要药材。');
/*!40000 ALTER TABLE `quiz_questions` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `quiz_record`
--

DROP TABLE IF EXISTS `quiz_record`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `quiz_record` (
  `id` int NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `user_id` int NOT NULL COMMENT '用户ID',
  `score` int NOT NULL COMMENT '得分',
  `total_questions` int NOT NULL COMMENT '总题数',
  `correct_answers` int NOT NULL COMMENT '正确数',
