  `favorite_count` int DEFAULT '0' COMMENT '收藏量',
  `update_log` text,
  PRIMARY KEY (`id`),
  KEY `idx_category` (`category`),
  KEY `idx_popularity` (`popularity`)
) ENGINE=InnoDB AUTO_INCREMENT=30 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='学习资源表';
