INSERT INTO `resources` (`id`, `title`, `category`, `files`, `description`, `download_count`, `popularity`, `created_at`, `view_count`, `favorite_count`, `update_log`) VALUES (1,'《贵州凯里药市的侗族药用植物》','入门','[{\"path\":\"documents/pdf/resources/cbd57b1f40334c2b943ced4190d1bea8.pdf\",\"name\":\"《贵州凯里药市的侗族药用植物》.pdf\",\"size\":646359,\"type\":\"pdf\"}]','本书为侗族医药入门读物，系统介绍了侗族医药的基本概念、发展历史、理论基础、常用药材、传统疗法等内容，适合初学者阅读学习。',12,156,'2026-03-04 04:47:10',14,1,'[{\"id\":1773739712398,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773668591698,\"time\":\"2026-03-16\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682001,\"time\":\"2026-03-04\",\"content\":\"创建学习资源：侗族医药入门指南\",\"operator\":\"系统\"}]'),(2,'【传统医学】 侗医药（过路黄药制作工艺）（贵州省黔东南苗族侗族自治州 国家级） - 非遗网-非遗商城-非物质文化遗产交易平台','专业','[{\"path\":\"documents/pdf/resources/925f17e04ca3406aac230b2f84dab72a.pdf\",\"name\":\"【传统医学】 侗医药（过路黄药制作工艺）（贵州省黔东南苗族侗族自治州 国家级） - 非遗网-非遗商城-非物质文化遗产交易平台.pdf\",\"size\":302563,\"type\":\"pdf\"}]','本视频详细介绍了侗族药浴疗法的历史渊源、功效作用、操作方法、注意事项等内容，并配有实际操作演示，适合初学者学习参考。',8,142,'2026-03-04 04:47:10',6,0,'[{\"id\":1773739539993,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773680533824,\"time\":\"2026-03-16\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682002,\"time\":\"2026-03-04\",\"content\":\"创建学习资源：侗族药浴疗法详解\",\"operator\":\"系统\"}]'),(3,'三江侗医药：从“脱离巫医”到“出山入粤','入门','[{\"path\":\"documents/pdf/resources/bbcdd5a093554106843396627e83c724.pdf\",\"name\":\"三江侗医药：从“脱离巫医”到“出山入粤” - 南方农村报.pdf\",\"size\":2549964,\"type\":\"pdf\"}]','本书收录了侗族地区常用草药100余种，每种药材配有高清图片、侗语名称、学名、功效主治、用法用量等信息，是学习侗族草药的重要参考资料。',15,178,'2026-03-04 04:47:10',21,1,'[{\"id\":1773743590901,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682003,\"time\":\"2026-03-04\",\"content\":\"创建学习资源：侗族常用草药图谱\",\"operator\":\"系统\"}]'),(4,'多元医疗-一个侗族村寨的个案研究','入门','[{\"path\":\"documents/pdf/resources/f519de3be11a4bd98e708f40c8d9c3a2.pdf\",\"name\":\"多元医疗-一个侗族村寨的个案研究.pdf\",\"size\":480602,\"type\":\"pdf\"}]','本视频系统介绍了侗族艾灸疗法的基本知识、穴位选择、操作方法、适应症与禁忌症等内容，适合初学者学习侗族艾灸疗法。',7,135,'2026-03-04 04:47:10',2,0,'[{\"id\":1773744515059,\"time\":\"2026-03-17\",\"content\":\"更新学习资源\",\"operator\":\"管理员\"},{\"id\":1773145682004,\"time\":\"2026-03-04\",\"content\":\"创建学习资源：侗族艾灸疗法教程\",\"operator\":\"系统\"}]'),(5,'侗族推拿手法图解','进阶','[{\"name\": \"dong_massage_guide.pdf\", \"path\": \"uploads/resources/dong_massage_guide.pdf\", \"size\": 5242880, \"type\": \"document\"}]','本书详细介绍了侗族推拿疗法的各种手法，包括推法、拿法、按法、摩法、揉法、捏法等，每种手法配有详细图解和操作要点，适合有一定基础的学习者。',6,128,'2026-03-04 04:47:10',1,0,'[{\"id\": 1773145682005, \"time\": \"2026-03-04\", \"content\": \"创建学习资源：侗族推拿手法图解\", \"operator\": \"系统\"}]'),(6,'侗族妇科疗法精要','进阶','[{\"name\": \"dong_gynecology.pdf\", \"path\": \"uploads/resources/dong_gynecology.pdf\", \"size\": 3145728, \"type\": \"document\"}]','本书系统介绍了侗族妇科疗法的理论基础、常用方剂、特色疗法等内容，重点介绍了侗族产后调理、月经不调、不孕不育等疾病的治疗方法。',5,112,'2026-03-04 04:47:10',0,0,'[{\"id\": 1773145682006, \"time\": \"2026-03-04\", \"content\": \"创建学习资源：侗族妇科疗法精要\", \"operator\": \"系统\"}]'),(7,'侗族儿科疗法精要','进阶','[{\"name\": \"dong_pediatrics.pdf\", \"path\": \"uploads/resources/dong_pediatrics.pdf\", \"size\": 2621440, \"type\": \"document\"}]','本书系统介绍了侗族儿科疗法的理论基础、常用方剂、特色疗法等内容，重点介绍了侗族小儿推拿、小儿发热、小儿咳嗽等疾病的治疗方法。',4,105,'2026-03-04 04:47:10',0,0,'[{\"id\": 1773145682007, \"time\": \"2026-03-04\", \"content\": \"创建学习资源：侗族儿科疗法精要\", \"operator\": \"系统\"}]'),(8,'侗族正骨疗法视频教程','进阶','[{\"name\": \"mov_bbb.mp4\", \"path\": \"https://www.w3schools.com/html/mov_bbb.mp4\", \"size\": 73400320, \"type\": \"video\"}]','本视频详细介绍了侗族正骨疗法的基本手法、骨折复位、脱臼复位、固定方法等内容，并配有实际操作演示，适合有一定基础的学习者。',4,98,'2026-03-04 04:47:10',0,0,'[{\"id\": 1773145682008, \"time\": \"2026-03-04\", \"content\": \"创建学习资源：侗族正骨疗法视频教程\", \"operator\": \"系统\"}]'),(9,'侗族蛇伤急救手册','专业','[{\"name\": \"dong_snake_bite.pdf\", \"path\": \"uploads/resources/dong_snake_bite.pdf\", \"size\": 1572864, \"type\": \"document\"}]','本书详细介绍了侗族蛇伤急救的方法，包括毒蛇识别、伤口处理、药物应用、急救步骤等内容，是侗医蛇伤治疗的专业参考资料。',3,8